-- Sullam at-Taufiq (Abdullah bin Husain bin Thahir Ba'alawi) — teks Arab
-- lengkap dari sumber terbuka (fatihsyuhud.org, matan penuh; pembukaan dan
-- urutan fasal diverifikasi terhadap struktur matn yang dikenal). Bagian
-- biografi milik blog TIDAK diikutkan. Idempoten: INSERT OR IGNORE.
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 100, 'مُقَدِّمَةُ المُؤَلِّف', 'مُقَدِّمَةُ المُؤَلِّف');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الحَمْدُ للهِ رَبِّ العالَمِينَ، وأشْهَدُ أنْ لا إلٰهَ إلّا اللهُ وَحْدَهُ لا شَرِيكَ لَهْ، وأشْهَدُ أنَّ مُحَمَّدًا عَبْدُهُ ورَسُولُهُ، صَلَّى اللهُ عليه وسَلَّمَ وعلى آلِهِ وصَحْبِهِ والتّابِعِين.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 100;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'أمّا بَعْدُ، فَهٰذا جُزْءٌ لَطِيفٌ يَسَّرَهُ اللهُ تَعالَى، فِيما يَجِبُ تَعَلُّمُهُ، وتَعْلِيمُهُ، والعَمَلُ بِهِ لِلخاصِّ والعامِّ، والواجِبُ ما وَعَدَ اللهُ فاعِلَهُ بِالثَّوابِ، وتَوَعَّدَ تارِكَهُ بِالعِقابِ، وسَمَّيْتُهُ سُلَّمَ التّوْفِيق إلى مَحَبَّةِ اللهِ على التَّحْقِيق، أسأَلُ اللهَ الكَرِيمَ أنْ يَجْعَلَ ذٰلك مِنْهُولَهُ وفِيهِ وإلَيْه، ومُوجِبًا لِلقُرْبِ والزُّلْفَى لَدَيْه، وأنْ يُوَفِّقَ مَنْ وَقَفَ عليه لِلْعَمَلِ بِمُقْتَضاه، ثُمَّ التَّرَقِّي بِالتَّوَدُّدِ بِالنَّوافِلِ لِيَحُوزَ حُبَّهُ ووَلاه.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 100;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 101, 'فَصْلٌ: في الواجِبِ على كُلِّ مُكَلَّفٍ', 'فَصْلٌ: في الواجِبِ على كُلِّ مُكَلَّفٍ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على كافَّةِ المُكَلَّفِينَ الدُّخُولُ في دِينِ الإسْلام، والثُّبُوتُ فيه على الدَّوام، والْتِزامُ ما لَزِمَ عليه مِنَ الأحْكام.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 101;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 102, 'فَصْلٌ: في مَعْنَى الشَّهادَتَيْنِ', 'فَصْلٌ: في مَعْنَى الشَّهادَتَيْنِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'فَمِمّا يَجِبُ عِلْمُهُ واعْتِقادُهُ مُطْلَقًا، والنُّطْقُ به في الحالِ إنْ كانَ كافِرًا، وإلّا ففي الصَّلاةِ، الشَّهادَتانِ وهُما: "أشْهَدُ أنْ لا إلٰهَ إلّا اللهُ، وأشْهَدُ أنَّ مُحَمَّدًا رَسُولُ اللهِ"، صلى الله عليه وسلم.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 102;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'مَعْنَى الشَّهادَةِ الأُولَى: ومَعْنَى أشْهَدُ أنْ لا إلٰهَ إلّا اللهُ: أنْ تَعْلَمَ وتَعْتَقِدَ وتُؤْمِنَ وتُصَدِّقَ أنْ لا مَعْبُودَ بِحَقٍّ في الوُجُودِ إلّا اللهُ، الواحِدُ، الأحَدُ، الأوَّلُ، القَدِيمُ، الحَيُّ، القَيُّومُ، الباقِي، الدائِمُ، الخالِقُ، الرّازِقُ، العالِمُ، القَدِيرُ، الفَعّالُ لما يُرِيدُ، ما شاءَ اللهُ كانَ وما لم يَشَأْ لم يَكُنْ، ولا حَوْلَ ولا قُوَّةَ إلّا بِاللهِ العَلِيِّ العَظِيمِ، مَوْصُوفٌ بِكُلِّ كَمالٍ، مُنَزَّهٌ عن كُلِّ نَقْصٍ، ﴿ لَيْسَ كَمثْلِهِ شَيْءٌ وهُوَ السَّمِيعُ البَصِيرُ ﴾، فهو القَدِيمُ وما سِواهُ حادِثٌ، وهو الخالِقُ وما سِواهُ مَخْلُوقٌ، وكَلامُهُ قَدِيمٌ [أي بِلا ابْتِداءٍ] كَسائِرِ صِفاتِهِ، لِأنَّهُ سُبْحانَهُ مُبايِنٌ لِجَمِيعِ المَخْلُوقاتِ في الذّاتِ والصِّفاتِ والأفْعال، [ومَهْما تَصَوَّرْتَ بِبالِك، فَاللهُ تَعالَى لا يُشْبِهُ ذلِك]، سُبْحانَهُ وتَعالَى عَمّا يَقُولُ الظّالِمُونَ عُلُوًّا كَبِيرًا.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 102;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'مَعْنَى الشَّهادَةِ الثّانِيَةِ: ومَعْنَى أشْهَدُ أنَّ مُحَمَّدًا رَسُولُ اللهِ: أنْ تَعْلَمَ وتَعْتَقِدَ وتُصَدِّقَ وتُؤْمِنَ أنَّ سَيِّدَنا ونَبِيَّنا مُحَمَّدَ بْنَ عَبْدِ اللهِ بْنِ عَبْدِ المُطَّلِبِ بْنِ هاشِمِ بْنِ عَبْدِ مَنافٍ القُرَشِيَّ صَلَّى اللهُ عليه وسَلَّمَ عَبْدُ اللهِ ورَسُولُهُ إلى جَمِيعِ الخَلْقِ؛ وُلِدَ بِمَكَّةَ، وبُعِثَ بِها، وهاجَرَ إلى المَدِينَةِ، ودُفِنَ فيها، وأنَّهُ صَلَّى اللهُ عليه وسَلَّمَ صادِقٌ في جَمِيعِ ما أخْبَرَ بِهِ [ومنه السَّمْعِيّاتِ الَّتِي لا تُعْرَفُ بِمُجَرَّدِ العَقْلِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 102;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 103, 'فَصْلٌ فِيما يَجِبُ الإيمانُ به مِنَ السَّمْعِيّاتِ', 'فَصْلٌ فِيما يَجِبُ الإيمانُ به مِنَ السَّمْعِيّاتِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'فَمِنْ ذٰلك عَذابُ القَبْرِ، ونَعِيمُهُ، وسُؤالُ المَلَكَيْنِ مُنْكَرٍ ونَكِيرٍ، والبَعْثُ، والحَشْرُ، والقِيامَةُ، والحِسابُ، والثَّوابُ، والعَذابُ، والمِيزانُ، والنّارُ، والصِّراطُ، والحَوْضُ، والشَّفاعَةُ، والجَنَّةُ، والخُلُودُ، والرُّؤْيَةُ للهِ سُبْحانَهُ وتَعالَى [لا كَما يُرَى المَخْلُوقُ، فَيَراهُ المُؤْمِنُونَ في الآخِرَةِ وهُمْ] في الجَنَّةِ [وقَبْلَ دُخُولِها] ، وأنْ تُؤمِنَ بِمَلائِكَةِ اللهِ، ورُسُلِهِ، وكُتُبِهِ، وبِالقَدَرِ خَيْرِهِ وشَرِّهِ، وأنَّهُ صَلَّى اللهُ عليه وسَلَّمَ خاتَمُ النَّبِيِّينَ وسَيِّدُ ولَدِ آدَمَ أجْمَعِينَ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 103;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 104, 'فَصْلٌ في خُلاصَةِ مَعْرِفَةِ اللهِ تَعالَى', 'فَصْلٌ في خُلاصَةِ مَعْرِفَةِ اللهِ تَعالَى');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ما يَجِبُ للهِ تَعالَى: خُلاصَةُ ما تَقَدَّمَ في مَعْنَى الشَّهادَةِ الأُولَى إثْباتُ ثَلاثَ عَشْرَةَ صِفَةً للهِ تَعالَى، أي اعْتِقادُ أنَّها مِنْ صِفاتِهِ تَعالَى الَّتِي لا حَدَّ لَها في العَدِّ، ولا يُحْصِيها أَحَدٌ مِنَ الخَلْقِ، وتَدُلُّ على الكَمالِ المُطْلَقِ؛ وهٰذه الصِّفاتُ الثّلاثَةَ عَشَرَ دَلَّ العَقْلُ على وُجُوبِها للهِ تَعالَى، بِمَعْنَى أنَّ العَقْلَ لا يَقْبَلُ ولا يُصَدِّقُ نَفْيَ أيٍّ منها عَنِ اللهِ تَعالَى، وقالَ العُلَماءُ إنَّه يَجِبُ مَعْرِفَتُها على كُلِّ مُكَلَّفٍ وُجُوبًا عَيْنِيًّا، لِأنَّها تَكَرَّرَ ذِكْرُها كَثِيرًا في النَّقْلَِ أي القُرْآنِ والحَدِيثِ، إمّا لَفْظًا وإمّا مَعْنًى؛ ولَيْسَتْ مَعْرِفَتُها الواجِبَةُ مَعرِفَةَ إحاطَةٍ بِحَقائِقِها، فَالخَلقُ جَمِيعًا عاجِزُونَ عن مَعْرِفَةِ حَقِيقَةِ اللهِ تَعالَى وصِفاتِهِ، فَلا يَعْرِفُ اللهَ على الحَقِيقَةِ إلّا اللهُ، وهي:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, '(1) صِفَةُ الوُجُودِ (2) وصِفَةُ الوَحْدانِيَّةِ (3) وصِفَةُ الأزَلِيَّةِ (4) وصِفَةُ البَقاءِ (5) وصِفَةُ عَدَمِ مُشابَهَةِ غَيْرِهِ (6) وصِفَةُ الاسْتِغْناءِ المُطْلَقِ عَنْ غَيْرِهِ (7) وصِفَةُ القُدْرَةِ (8) وصِفَةُ الإرادَةِ (9) وصِفَةُ العِلْمِ (10) وصِفَةُ السَّمْعِ (بِلا أُذُنٍ) (11) وصِفَةُ البَصَرِ (بِلا عَيْنٍ) (12) وصِفَةُ الحَياةِ (بِلا رُوحٍ) (13) وصِفَةُ الكَلامِ (بِلا حَرْفٍ ولا صَوْتٍ ولا لُغَةٍ)', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'وصِفاتُ الأُلُوهِيَّةِ هٰذه لا تَتَغَيَّرُ فَلَيْسَتْ طارِئَةً بَلْ هي صِفاتٌ للهِ بِلا ابْتِداءٍ، لأنَّ صِفاتِ الأَزَلِيِّ لا تَكُونُ إلّا أَزَلِيَّةً، ولا شَبَهَ بَيْنَ صِفاتِ اللهِ وبَيْنَ ما يُسَمَّى بِأَسْمائِها مِنْ صِفاتِ المَخْلُوقاتِ، وإنْ كانَتِ المَعانِي اللُّغَوِيَّةُ لِما يُسَمَّى بِاسْمِها مِنْ صِفاتِ المَخْلُوقاتِ تُقَرِّبُ لِعُقُولِنا فَهْمَ ما يُمْكِنُنا فَهْمُهُ عَنْها، مَعَ اسْتِحْضارِ أَنَّهُ لَيْسَ بَيْنَ صِفاتٍ الخَلْقِ وصِفاتِ الحَقِّ اشْتِراكٌ أَصْلًا ولا مُشابَهَةٌ بَتاتًا.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'ما يَسْتَحِيلُ على اللهِ تَعالَى: وحُكْمُ العَقْلِ بِوُجُوبِ هٰذِهِ الصِّفاتِ المَذْكُورَةِ للهِ تَعالَى يَعْنِي أنَّ العَقْلَ لا يَقْبَلُ ولا يُصَدِّقُ أنْ يَكُونَ اللهُ مُتَّصِفًا بأَضْدادِها، أي أنَّ العَقْلَ يَحْكُمُ أيْضًا بِاسْتِحالَةِ صِفاتِ النَّقْصِ الَّتِي تُقابِلُها وتُنافِيها عليه تَعالَى، ويَنْفِيها قَطْعًا عنه تَعالَى، وكذٰلك النَّقْلُ يَدُلُّ على انْتِفائِها عنه تَعالَى، وهي: (1) العَدَمُ (2) والتَّعَدُّدُ (3) والابْتِداءُ (4) والانْتِهاءُ', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, '(5) ومُشابَهَةُ غَيْرِهِ (6) والاحْتِياجُ إلى غَيْرِهِ (7) والعَجْزُ عن شَيْءٍ (8) وأنْ يَكُونَ مُكْرَها على أمْرٍ، أو بِلا اخْتِيارٍ في فِعْلٍ (9) والجَهْلُ بِشَيْءٍ (10) والصَّمَمُ (11) والعَمَى (12) والمَوْتُ (13) والبَكَمُ (بِمَعْنَى انْتِفاءِ صِفَةِ الكَلامِ الأزَلِيِّ الذي لَيْسَ بِلُغَةٍ وصَوْتٍ عنه تَعالَى)', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 6, NULL, NULL, 'ما يَجُوزُ في حَقِّ اللهِ تَعالَى: ودَلَّ العَقْلُ والنَّقْلُ أيْضًا على أنَّهُ يَجُوزُ أنْ يُوجِدَ اللهُ أيَّ مُمكِنٍ أو يَتْرُكَ إيجادَهُ، ولٰكِنَّهُ تَعالَىٰ لا يُوجِدُ إلّا ما سَبَقَ في عِلْمِهِ الأزَليِّ ومَشِيئَتِهِ الأزَلِيَّةِ أنَّهُ يَدْخُلُ في الوُجُودِ، فَيُوجِدُ اللهُ تَعالَى المَخْلُوقَ في وَقْتِهِ على حَسَبِ ما عَلِمَهُ اللهُ وشاءَهُ بِلا ابْتِداءٍ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 105, 'فَصْلٌ : في الدَّلِيلِ الإجْمالِيِّ على وُجُودِ اللهِ وصِفاتِهِ', 'فَصْلٌ : في الدَّلِيلِ الإجْمالِيِّ على وُجُودِ اللهِ وصِفاتِهِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على المُكَلَّفِ أنْ يَعْرِفَ الدَّلِيلَ الإجْمالِيَّ على وُجُودِ اللهِ تَعالَى وصِفاتِهِ لِيُحَصِّنَ إيمانَه، ومِثالُهُ أنْ يَقُولَ في نَفْسِهِ: أنا وُجِدْتُ في بَطْنِ أُمِّي، بَعْدَ أنْ لَمْ أكُنْ مَوْجُودًا، ومَنْ وُجِدَ بَعْدَ أنْ لَمْ يَكُنْ فَلا بُدَّ لَهُ مِنْ مُوجِدٍ أي خالِقٍ أوْجَدَهُ وكَوَّنَهُ، فَلا بُدَّ لِي مِنْ خالِقٍ خَلَقَ لِي أعْضائِيَ وأجْزائِيَ وتَفاصِيلِيَ الدَّاخِلِيَّةَ والخارِجِيَّةَ، وذٰلِكَ المُكَوِّنُ الَّذِي كَوَّنَنِي وأوْجَدَنِي لَيْسَ أبِي ولا أُمِّي ولا أيَّ مَخْلُوقٍ آخَرَ، بَلْ هُوَ خالِقٌ عَظِيمٌ، خَلَقَ كُلَّ مَا في هَذَا الكَوْنِ، ويُسَيطِر على كُلِّ ذرَّةٍ مِنْ ذرّاتِهِ سَيْطَرَةً تامَّة، فهو إلٰه واحِدٌ، لا شَرِيكَ ولا مَثِيلَ لَهُ، وهُوَ مُنَزَّهٌ عَنْ كُلِّ نَقْصٍ، فَلَهُ الكَمالُ المُطْلَقُ غَيْرُ المَحْدُودِ، فَلا بُدَّ أنْ يَكُونَ مُتَّصِفًا بِالعِلْمِ والقُدْرَةِ والإرادَةِ والحَياةِ وسائِرِ صِفاتِ الكَمالِ على ما يَلِيقُ بِالأُلُوهِيَّةِ، وعُقُولُ الخَلْقِ لا تُحِيطُ بِهِ عِلْمًا، ويُسَمَّى بِالعَرَبِيَّةِ "اللهَ".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 105;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 106, 'فصل في جَوابِ مَنْ يَسْأَلُ: "ما هُوَ اللهُ؟', 'فصل في جَوابِ مَنْ يَسْأَلُ: "ما هُوَ اللهُ؟');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'مِنَ المُهِمِّ أَنْ يَعْرِفَ المُسْلِمُ كَيْفَ يُجِيبُ مَنْ يَسْأَلُ: "ما هُوَ اللهُ؟"، فَهَذا سُؤالٌ يَطْرَحُهُ كَثِيرٌ مِنَ الصِّغارِ، ولا يُحْسِنُ الإِجابَةَ عَلَيْهِ كَثِيرٌ مِنَ الكِبارِ؛ ويُمْكِنُ إجابَتُهُ إجابَةً صَحِيحَةً بِأَنْ يُقالَ: اللهُ تَعالَى مَوْجُودٌ لا يُشْبِهُ غَيْرَهُ مِنَ المَوْجُوداتِ، فَمَهْما تَصَوَّرْتَ بِبالِكَ فَاللهُ لا يُشْبِهُ ذٰلك، ولا يَعْلَمُ أَحَدٌ غَيْرُهُ تَعالَى حَقِيقَتَهُ، ولٰكِنَّنا بِناءً على الأَدِلَّةَ القَطْعِيَّةَ نَعْلَمُ يَقِينًا عَنِ اللهِ تَعالَى أُمُورًا مِنْها:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'حَقِيقَةُ اللهِ تَعالَى لَيْسَتْ كَحَقِيقَةِ أَحَدٍ غَيْرِهِ، فَلَيْسَ تَعالَى مِنْ أَفْرادِ الكَوْنِ أي العالَمِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'لَيْسَ اللهُ تَعالَى في أيِّ مَكانٍ أو جِهَةٍ؛ لِأَنَّهُ لَيْسَ ذا جِسْمٍ وحَجْمٍ وشَكْلٍ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'لا يَحْتاجُ الله تعالى إِلى شَيْءٍ، ولا يَتَضَرَّرُ بشيءٍ، ولا يَنْتَفِعُ بِشَيْءٍ؛ لِأَنَّ لَهُ الكَمالَ المُطْلَقَ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'اللهُ تَعالَى لا بِدايَةَ لِوُجُودِهِ، فَلَيْسَ لَهُ خالِقٌ كَغَيْرِهِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 6, NULL, NULL, 'اللهُ تَعالَى خالِقُ كُلِّ ما سِواهُ، أيِ كُلِّ ما في العالَمِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 7, NULL, NULL, 'ما أَوْهَمَتْ ظَواهِرُهُ مِنَ الآياتِ الكَرِيمَةِ والأَحادِيثِ الشَّرِيفَةِ اتِّصافَ اللهِ تَعالَى بِصِفَةٍ مِنْ صِفاتِ المَخْلُوقاتِ، كَالجِسْمِ والمَكانِ والحَرَكَةِ والسُّكُونِ، فَتَفْسِيرُهُ الصَّحِيحُ غَيْرُ ذٰلك قَطْعًا.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 8, NULL, NULL, 'خُلاصَةٌ في مَعْرِفَةِ الأَنْبِياءِ عليهم الصَّلاةُ والسَّلامُ', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 9, NULL, NULL, 'المُعْجِزاتُ دَلِيلٌ قاطِعٌ على صِدْقِ الأَنْبِياءِ: ويَجِبُ اعْتقادُ أنَّ المُعْجِزاتِ دَلِيلٌ يَقِينِيٌّ على صِدْقِ الأَنْبِياءِ، الَّذِينَ هُمْ أَفْضَلُ خَلْقِ اللهِ تَعالَى، وسُفَراؤُهُ إلى غَيْرِهِمْ مِنْ خَلْقِهِ، وهي خَوارِقُ لِلعاداتِ الكَوْنِيَّةِ في الدُّنْيا أيَّدَهُمُ اللهُ بِها وخصَّهُمْ بِها إظْهارًا لِتَصْدِيقِهِ لَهُمْ، وجَعَلَها مُوافِقَةً لِدَعْواهُمُ النُّبوَّةَ، وأعْجَزَ عن الإتْيانِ بِمِثْلِها كُلَّ مُتَنَبِّئٍ زُورًا وكلَّ مُكَذِّبٍ لأحَدٍ مِنَ الأنْبِياءِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 10, NULL, NULL, 'ما يَجِبُ لِلْأَنْبِياءِ: ويَجِبُ اعْتقادُ أنَّ كُلَّ نَبِيٍّ مِنْ أنْبِياءِ اللهِ عليهم الصَّلاةُ والسَّلامُ يَجِبُ لَهُ - بالدَّلِيلِ العَقْلِيِّ أو بِالدَّلِيلِ الشَّرْعِيِّ أو بِهِما مَعًا - صِفاتٌ حَمِيدَةٌ، منها: (1) الصِّدْقُ (2) والأمانَةُ (3) والتَّبْلِيغُ (4) والفَطانَةُ (5) والصِّيانَةُ (وهي البُعْدُ عَمّا يَعِيبُ) (6) والعِصْمَةُ مِنَ الكُفْرِ وسائِرِ الذُّنُوبِ كَبِيرِها وصَغِيرِها، قَبْلَ النُّبُوَّةِ وبَعْدَها', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 11, NULL, NULL, 'ما يَسْتَحِيلُ على الأَنْبِياءِ: يَسْتَحِيلُ على أيٍّ مِنَ الأنْبِياءِ أضْدادُ الصِّفاتِ الواجِبَةِ لَهُمْ، فَمِمّا يَسْتَحِيلُ عَلَيْهِمُ: (1) الكَذِبُ (2) والخِيانَةُ (3) وكِتْمانُ شَيْءٍ أَمَرَهُمُ اللهُ تَعالَى بِتَبْلِيغِهِ (4) والرَّذالَةُ (5) والسَّفاهَةُ (6) والهَزِيمَةُ (7) والخِسَّةُ', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 12, NULL, NULL, '(8) والغَباوَةُ (9) والكُفْرُ (10) وما يُكْتَبُ عليهم بِهِ ذَنْبٌ، قَبْلَ النُّبُوَّةِ وبَعْدَها؛ وكُلُّ عِبارَةٍ، مِمّا ثَبَتَ عن اللهِ تَعالَى أو عن رَسُولِهِ صَلَّى اللهُ عليه وسَلَّمَ، إذا أوْهَمَ ظاهِرُها خِلافَ ما يَجِبُ لْلأنْبِياءِ، فَتَفْسِيرُها الصَّحِيحُ غَيْرُ ظاهِرِها.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 13, NULL, NULL, 'ما يَجُوزُ في حَقِّ الأَنْبِياءِ: ويَجِبُ اعْتِقادُ أنَّ جَمِيعَ الأنْبِياءِ بَشَرٌ فَيَجُوزُ عليهم الأعْراضُ البَشرِيَّةُ الَّتي لا تُنافِي مَقامَهُمْ ومُهِمَّتَهُمْ وما يَجِبُ لَهُم؛ فَيَجُوزُ عليهم الأَكْلُ، والشُّرْبُ، والزَّواجُ، والمَرَضُ غيرُ المُنَفِّرِ منهم وغيرُ المُخِلِّ بِدَعْوَتِهِمْ، ونَوْمُ العَيْنِ لا القَلْبِ، والمَوْتُ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 107, 'فَصْلٌ : فِيما يُخرِجُ مِنَ الإسْلامِ', 'فَصْلٌ : فِيما يُخرِجُ مِنَ الإسْلامِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على كُلِّ مُسْلِمٍ حِفْظُ إسْلامِهِ وصَوْنُهُ عَمّا يُفْسِدُهُ ويُبْطِلُهُ ويَقْطَعُهُ، وهو الرِّدَّةُ [أيِ الكُفْرُ بَعْدَ الإسْلامِ] والعِياذُ بِاللهِ تَعالَى، وقَدْ كَثُرَ في هذا الزَّمانِ التَّساهُلُ في الكَلامِ حَتَّى إنَّهُ يَخْرُجُ مِنْ بَعْضِهِمْ ألْفاظٌ تُخْرِجُهُمْ عن الإسْلامِ، ولا يَرَوْنَ ذٰلك ذَنْبًا فَضْلًا عن كَوْنِهِ كُفْرًا، والرِّدَّةُ ثَلاثَةُ أقْسامٍ: اعْتِقاداتٌ وأفْعالٌ وأقْوالٌ، وكُلُّ قِسْمٍ يَتَشَعَّبُ شُعَبًا كَثِيرَةً.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'أمْثِلَةُ الرِّدَّةِ بِالقَلْبِ (أيِ الاعْتِقاداتِ الكُفْرِيَّةِ): فَمِنَ الأوَّلِ:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'الشَّكُّ في اللهِ، أو في رَسُولِهِ، أو القُرْآنِ، أو اليَوْمِ الآخِرِ، أو الجَنَّةِ، أو النّارِ، أو الثَّوابِ، أو العِقابِ، ونَحْوِ ذٰلك مِمّا هو مُجمَعٌ عليه [مَعْلُومٌ مِنَ الدِّينِ بِالضَّرُورَةِ مِمّا لا يَخْفَى عليه]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'أو [مَنِ] اعتَقَدَ فَقْدَ [أي نَفْيَ] صِفَةٍ مِنْ صِفاتِ اللهِ الواجِبَةِ إجْماعًا [ممّا دلَّ عليه العَقْلُ] كَالعِلْمِ، أو [مَنْ] نَسَبَ له [تَعالَى] صِفَةً يَجِبُ تَنْزِيهُهُ عنها إجْماعًا [مِمّا يَدُلُّ العَقْلُ على أنَّهُ نَقْصٌ في حَقِّهِ تَعالَى]، كَالجِسْمِ، أو [مَنْ] حَلَّلَ مُحَرَّمًا بِالإجْماعِ مَعْلُومًا مِنَ الدِّينِ بِالضَّرُورَةِ مِمّا لا يَخْفَى عليه، كالزِّنا واللِّواطِ والقَتْلِ والسَّرِقَةِ والغَصْبِ [أي أَخْذِ أَمْوالِ النّاسِ بِغَيْرِ حَقٍّ قَهْرًا]؛ أو [مَنْ] حَرَّمَ حَلالًا كذٰلك [أي مِمّا هو مَعْلُومٌ مِنَ الدِّينِ بِالضَّرُورَةِ مِمّا لا يَخْفَى عليه]، كالبَيْعِ والنِّكاحِ؛ أو [مَنْ] نَفَى وُجُوبَ مُجْمَعٍ عليه كذٰلك [أي مِمّا هو مَعْلُومٌ مِنَ الدِّينِ بِالضَّرُورَةِ مِمّا لا يَخْفَى عليه]، كَالصَّلَواتِ الخَمْسِ، أو سَجْدَةٍ منها، والزَّكاةِ، والصَّوْمِ، والحَجِّ، والوُضُوءِ؛ أو [مَنْ] أوْجَبَ ما لم يَجِبْ إجْماعًا كذٰلك [أي مِمّا هو مَعْلُومٌ مِنَ الدِّينِ بِالضَّرُورَةِ مِمّا لا يَخْفَى عليه]؛ أو [مَنْ] نَفَى مَشْرُوعِيَّةَ مُجْمَعٍ عليه كذٰلك [أي مِمّا هو مَعْلُومٌ مِنَ الدِّينِ بِالضَّرُورَةِ مِمّا لا يَخْفَى عليه]، كَالرَّواتِبِ؛ أو [مَنْ] عَزَمَ على الكُفْرِ [مُطْلَقًا] في المُسْتَقْبَلِ؛ أو [مَنْ عَزَمَ] على فِعْلِ شَيْءٍ مِمّا ذُكِرَ [مِنَ الكُفْرِيّاتِ أو نَحْوِها في المُسْتَقْبَلِ]، أو تَرَدَّدَ فيه، لا وَسْوَسَةٌ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'أو [مَنْ] أنْكَرَ صُحْبَةَ سَيِّدِنا أبِي بَكْرٍ رَضِيَ اللهُ عنه؛ أو [مَنْ أنْكَرَ] رِسالَةَ واحِدٍ مِنَ الرُّسُلِ المُجْمَعِ على رِسالَتِهِ [أي مِمَّنْ رِسالَتُهُ مِنَ المَعْلُومِ مِنَ الدِّينِ بِالضَّرُورَةِ الَّذِي لا يَخْفَى عليه، كَسَيِّدِنا عِيسَى وسَيِّدِنا مُوسَى عليهما الصَّلاةُ والسَّلامُ]؛ أو [مَنْ] جَحَدَ حَرْفًا مُجْمَعًا عليه مِنَ القُرْآنِ [وهو يَعْتَقِدُ أنَّهُ منه]، أو زادَ حَرْفًا فيه مُجْمَعًا على نَفْيِهِ [مَعَ كَوْنِهِ] مُعْتَقِدًا أنَّهُ [لَيْسَ] منه؛ أو [مَنْ] كَذَّبَ رَسُولًا، أو نَقَّصَهُ، أو صَغَّرَ اسْمَهُ بِقَصْدِ تَحْقِيرِهِ؛ أو [مَنْ] جَوَّزَ نُبُوَّةَ أحَدٍ بَعْدَ نَبِيِّنا مُحَمَّدٍ صَلَّى اللهُ عليه وسَلَّمَ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 6, NULL, NULL, 'أمْثِلَةُ الرِّدَّةِ بِالجَوارِحِ (أي الأفْعالِ الكُفْرِيَّةِ):', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 7, NULL, NULL, 'والقِسْمُ الثّاني أفْعالٌ، كَسُجُودٍ لِصَنَمٍ أو شَمْسٍ أو قَمَرٍ [أو شَيْطانٍ] [مُطْلَقًا]، أو مَخْلُوقٍ آخَرَ [على وَجْهِ عِبادَتِهِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 8, NULL, NULL, 'أمْثِلَةُ الرِّدَّةِ بِاللِّسانِ (أي الأقْوالِ الكُفْرِيَّةِ):', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 9, NULL, NULL, 'والقِسْمُ الثّالِثُ الأقْوالُ، وهي كَثِيرَةٌ جِدًّا لا تَنْحَصِرُ، منها:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 10, NULL, NULL, 'أنْ يَقُولَ [الشَّخْصُ] لِمُسْلِمٍ: "يا كافِرُ"، أو "يا يَهُودِيُّ"، أو "يا نَصْرانيُّ"، أو "يا عَدِيمَ الدِّينِ"، مُرِيدًا أنَّ الَّذِي عليه المُخاطَبُ مِنَ الدِّينِ كُفْرٌ أو يَهُودِيَّةٌ أو نَصْرانِيَّةٌ أو لَيْسَ بِدِينٍ؛ وكَالسُّخْرِيَةِ بِاسْمٍ مِنْ أسْمائِهِ تَعالَى أو وَعْدِهِ أو وَعِيدِهِ، مِمَّن لا يَخْفَى عليه نِسْبَةُ ذٰلك إليه سُبْحانَهُ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 11, NULL, NULL, 'وكَأنْ يَقُولَ [الشَّخْصُ]: "لَوْ أمَرَنِي اللهُ بِكَذا لم أفْعَلْهُ"، أو [يَقُولَ الشَّخْصُ]: "لَوْ صارَتِ القِبْلَةُ في جِهَةِ كَذا ما صَلَّيْتُ إليها"، أو [يَقُولَ الشَّخْصُ]: "لَوْ أعْطانِي اللهُ الجَنَّةَ ما دَخَلْتُها"، مُسْتَخِفًّا، أو مُظهِرًا لِلْعِنادِ، في الكُلِّ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 12, NULL, NULL, 'وكَأنْ يَقُولَ [الشَّخْصُ]: "لَوْ آخَذَنِي اللهُ بِتَرْكِ الصَّلاةِ مَعَ ما أنا فيه مِنَ المَرَضِ ظَلَمَنِي"؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 13, NULL, NULL, 'أو قالَ [الشَّخْصُ] لِفِعْلٍ: "حَدَثَ هذا بِغَيْرِ تَقْدِيرِ اللهِ"؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 14, NULL, NULL, 'أو [قالَ الشَّخْصُ]: "لَوْ شَهِدَ عِنْدِي الأنْبِياءُ أو المَلائِكَةُ أو جَمِيعُ المُسْلِمِينَ بِكَذا ما قَبِلْتُهُمْ"؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 15, NULL, NULL, 'أو قالَ [الشَّخْصُ]: "لا أفعَلُ كَذا وإنْ كانَ سُنَّةً" بِقَصْدِ الاسْتِهْزاءِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 16, NULL, NULL, 'أو [قالَ الشَّخْصُ]: "لَوْ كانَ فُلانٌ نَبِيًّا ما آمَنْتُ به"؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 17, NULL, NULL, 'أو أعْطاهُ عالِمٌ فَتْوَى فَقالَ [الشَّخْصُ]: "أَيْشٍ هذا الشَّرْعُ" مُرِيدًا الاسْتِخْفافَ [بِحُكْمِ الشَّرْعِ]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 18, NULL, NULL, 'أو قالَ [الشَّخْصُ]: "لَعْنَةُ اللهِ على كُلِّ عالِمٍ" مُرِيدًا الاسْتِغْراقَ الشّامِلَ [لِعُلَماءِ الدِّينِ الإسْلامِيِّ أو] لِأحَدِ الأنْبِياءِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 19, NULL, NULL, 'أو قالَ [الشَّخْصُ]: "أنا بَرِيءٌ مِنَ اللهِ" أو "مِنَ المَلائِكَةِ" أو "مِنَ النَّبِيِّ" أو "مِنَ القُرْآنِ" أو "مِنَ الشَّرِيعَةِ" أو "مِنَ الإسْلامِ"؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 20, NULL, NULL, 'أو قالَ [الشَّخْصُ] لِحُكْمٍ حُكِمَ بِهِ مِنْ أحْكامِ الشَّرِيعَةِ: "لَيْسَ هذا الحُكْمُ" أو "لا أعْرِفُ الحُكْمَ" مُسْتَهْزِئًا بِحُكْمِ اللهِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 21, NULL, NULL, 'أو قالَ [الشَّخْصُ] وقَدْ مَلَأَ وِعاءً: "﴿وَكَأْسًا دِهَاقًا﴾"، أو أفْرَغَ شَرابًا: "﴿فَكَانَتْ سَرَابًا﴾"، أو عِنْدَ وَزْنٍ أو كَيْلٍ: "﴿وَإِذَا كَالُوهُمْ أَوْ وَزَنُوهُمْ يُخْسِرُونَ﴾"، أو عِنْدَ رُؤْيَةِ جَمْعٍ: "﴿وَحَشَرْنَاهُمْ فَلَمْ نُغَادِرْ مِنْهُمْ أَحَدًا﴾"، بِقَصْدِ الاسْتِخْفافِ أو الاسْتِهْزاءِ [بِهٰذِهِ الآياتِ] في الكُلِّ؛ فإنْ كانَ بِغَيْرِ ذٰلك القَصْدِ [ونَحْوِهِ] فَلا يَكْفُرُ لٰكِنْ قالَ الشَّيْخُ أحْمَدُ بْنُ حَجَرٍ رَحِمَهُ اللهُ: "لا تَبْعُدُ حُرمَتُهُ"؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 22, NULL, NULL, 'وكَذا يَكْفُرُ مَنْ شَتَمَ نَبِيًّا أو مَلَكًا [بِفَتْحِ اللّامِ، أي واحِدًا مِنَ المَلائِكَةِ]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 23, NULL, NULL, 'أو قالَ [الشَّخْصُ]: "أكُونُ قَوّادًا إنْ صَلَّيْتُ"، أو [قالَ]: "ما أصَبْتُ خَيْرًا مُنْذُ صَلَّيْتُ"، أو [قالَ]: "الصَّلاةُ لا تَصْلُحُ لِي"، بِقَصْدِ الاسْتِخْفافِ بِها، أو الاسْتِهْزاءِ، أو اسْتِحْلالِ تَرْكِها، أو التَّشاؤُمِ بِها؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 24, NULL, NULL, 'أو قالَ [الشَّخْصُ] لِمُسْلِمٍ: "أنا عَدَوُّكَ وعَدُوُّ نَبِيِّكَ"، أو [قالَ] لِشَرِيفٍ: "أنا عَدُوُّكَ وعَدُوُّ جَدِّكَ" مُرِيدًا النَّبِيَّ صَلَّى اللهُ عليه وسَلَّمَ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 25, NULL, NULL, 'أو [أنْ] يَقُولَ [الشَّخْصُ] شَيْئًا مِنْ نَحْوِ هٰذِهِ الألْفاظِ البَشِعَةِ الشَّنِيعَةِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 26, NULL, NULL, 'وقَدْ عَدَّ الشَّيْخُ أحْمَدُ ابْنُ حَجَرٍ والقاضِي عِياضٌ رَحِمَهُما اللهُ في كِتابَيْهِما "الإعْلامُ" و"الشِّفا" شَيْئًا كَثِيرًا [مِنَ المُكَفِّراتِ] ، فَيَنْبَغِي الاطِّلاعُ عليه، فَإنَّ مَنْ لم يَعْرِفِ الشَّرَّ يَقَعْ فيه.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 108, 'قاعِدَةٌ لِمَعْرِفَةِ كَثِيرٍ مِنَ الكُفْرِ:', 'قاعِدَةٌ لِمَعْرِفَةِ كَثِيرٍ مِنَ الكُفْرِ:');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وحاصِلُ [أيْ حُكْمُ] أَكْثَرِ تلْكَ العِباراتِ يَرْجِعُ إلى [قاعِدَةِ] أنَّ كُلَّ عَقْدٍ أو فِعْلٍ أو قَوْلٍ يَدُلُّ على اسْتِهانَةٍ أو اسْتِخْفافٍ بِاللهِ، أو كُتُبِهِ، أو رُسُلِهِ، أو مَلائِكَتِهِ، أو شَعائِرِ أو مَعالِمِ دِينِهِ، أو أحْكامِهِ، أو وَعْدِهِ، أو وَعِيدِهِ، كُفْرٌ ومَعْصِيَةٌ، فَلْيَحْذَرِ الإنْسانُ مِنْ ذٰلك جَهْدَهُ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 108;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 109, 'فَصْلٌ : في بَعْضِ أحْكامِ المُرْتَدِّ', 'فَصْلٌ : في بَعْضِ أحْكامِ المُرْتَدِّ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على مَنْ وَقَعَتْ مِنْهُ رِدَّةٌ [أي كَفَرَ بَعْدَ أنْ كانَ مُسْلِمًا]: العَوْدُ فَوْرًا إلى الإسْلامِ: بِالنُّطْقِ بِالشَّهادَتَيْنِ، والإقْلاعِ عَمّا وَقَعَتْ به الرِّدَّةُ؛ ويَجِبُ عليه [أيْضًا]: النَّدَمُ على ما صَدَرَ منه، والعَزْمُ على أنْ لا يَعُودَ لِمِثْلِهِ، وقَضاءُ ما فاتَهُ مِنْ واجِباتِ الشَّرْعِ في تِلْكَ المُدَّةِ [كالصَّلَواتِ المَفْرُوضَةِ]؛ فإنْ لم يَتُبْ [أي فإنْ لم يَرْجِعْ عن كُفْرِهِ بِالشَّهادَتَيْنِ] وَجَبَتِ اسْتِتابَتُهُ [أي أمْرُهُ بِالرُّجُوعِ إلى الإسْلامِ بِالشَّهادَتَيْنِ]، ولا يُقبَلُ منه إلّا الإسْلامُ أو القَتْلُ [يُنَفِّذُهُ عليه الخَلِيفَةُ بِشُرُوطٍ مَذْكُورَةٍ في المُطَوَّلاتِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 109;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'و[مِمّا يَتَرَتَّبُ على رِدَّةِ الشَّخْصِ أنَّهُ:] [تَذْهَبُ بِها حَسَناتُهُ] ، يَبْطُلُ بِها صَوْمُهُ [للنَّهارِ الَّذِي ارْتَدَّ فيه]، و [يَبْطُلُ بِها] تَيَمُّمُهُ، و[يَبْطُلُ بِها] نِكاحُهُ [أي زَواجُهُ] قَبْلَ الدُّخُولِ، وكَذا بعدَهُ إنْ لم يَعُدْ إلى الإسْلامِ في العِدَّةِ، ولا يَصِحُّ عَقْدُ نِكاحِهِ [ولَوْ على مُرْتَدَّةٍ مِثْلِهِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 109;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'وتَحْرُمُ ذَبِيحَتُهُ [وتَكُونُ نَجِسَةً]، ولا يَرِثُ، ولا يُورَثُ، ولا يُصَلَّى عليه [ويَكْفُرُ مَنْ يُصَلِّي عليه وهو عالِمٌ بِحالِهِ]، ولا يُغَسَّلُ [أي لا يَجِبُ]، ولا يُكَفَّنُ [أي لا يَجِبُ]، ولا يُدْفَنُ [أي لا يَجِبُ]، [ويَحْرُمُ دَفْنُهُ في مَدافِنِ المُسْلِمِينَ]، ومالُهُ [بَعْدَ مَوْتِهِ] فَيْءٌ [أي لِمَصالِحِ المُسْلِمِينَ]، [ويُخَلَّدُ بِلا نِهايَةٍ في العَذابِ إنْ ماتَ على رِدَّتِهِ، كَغَيْرِهِ مِمَّنْ يَمُوتُ على غَيْرِ الإسْلامِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 109;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 110, 'فَصْلٌ : فِيما ما يَجِبُ على المُكَلَّفِ', 'فَصْلٌ : فِيما ما يَجِبُ على المُكَلَّفِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على كُلِّ مُكَلَّفٍ أداءُ جَمِيعِ ما أوْجَبَهُ اللهُ عليه، ويَجِبُ أنْ يُؤَدِّيَهُ على ما أمَرَهُ اللهُ بِهِ، مِنَ الإتْيانِ بِأرْكانِهِ وشُرُوطِهِ، وتَجَنُّبِ مُبْطِلاتِهِ، ويَجِبُ عليه أمْرُ مَنْ رَآهُ تارِكًا لِشَيْءٍ منها أو يَأتِي بِها على غيرِ وَجْهِها [بأدائِها على وَجْهِها]، ويَجِبُ عليه قَهْرُهُ على ذٰلك إنْ قَدِرَ، وإلّا فَيَجِبُ عليه الإنْكارُ بِقَلْبِهِ إنْ عَجَزَ عن القَهْرِ والأمْرِ، وذٰلك أضْعَفُ الإيمانِ، أي أقَلُّ ما يَلْزَمُ الإنْسانَ عند العَجْزِ؛ ويَجِبُ تَرْكُ جَمِيعِ المُحَرَّماتِ، ونَهْيُ مُرْتَكِبِها ومَنْعُهُ قَهْرًا منها إنْ قَدِرَ عليه، وإلّا وَجَبَ عليه أنْ يُنْكِرَ ذٰلك بِقَلْبِهِ ومُفارَقَةُ مَوْضِعِ المَعْصِيَةِ؛ والحَرامُ ما تَوَعَّدَ اللهُ مُرْتَكِبَهُ بِالعِقابِ ووَعَدَ تارِكَهُ بِالثَّوابِ [وعَكْسُهُ الواجِبُ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 110;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 111, 'فَصْلٌ : في أوْقاتِ الصَّلَواتِ المَفْرُوضَةِ', 'فَصْلٌ : في أوْقاتِ الصَّلَواتِ المَفْرُوضَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'فَمِنَ الواجِبِ خَمْسُ صَلَواتٍ في اليَوْمِ واللَّيْلَةِ: الظُّهْرُ: ووَقْتُها إذا زالَتِ الشَّمْسُ [أي مالَتْ عَنْ وَسَطِ السَّماءِ إلى جِهَةِ الغَرْبِ]، إلى مَصِيرِ ظِلِّ كُلِّ شَيْءٍ مِثْلَهُ غَيْرَ ظِلِّ الاسْتِواءِ؛ والعَصْرُ: ووَقْتُها مِنْ بَعْدِ [انْتِهاءِ] وَقْتِ الظُّهْرِ إلى مَغِيبِ الشَّمْسِ؛ والمَغْرِبُ: ووَقْتُها مِنْ بَعْدِ مَغِيبِ الشَّمْسِ، إلى مَغِيبِ الشَّفَقِ الأَحْمَرِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 111;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والعِشاءُ: ووَقْتُها مِنْ بَعْدِ [انْتِهاءِ] وَقْتِ المَغْرِبِ، إلى طُلُوعِ الفَجْرِ الصّادِقِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 111;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'والصُّبْحُ: ووَقْتُها مِنْ بَعْدِ [انْتِهاءِ] وَقْتِ العِشاءِ إلى طُلُوعِ الشَّمْسِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 111;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'فَتَجِبُ هٰذِهِ الفُرُوضُ في أَوْقاتِها على كُلِّ مُسْلِمٍ، بالِغٍ، عاقِلٍ، طاهِرٍ؛ فَيَحْرُمُ تَقْدِيمُها على وَقْتِها وتَأْخِيرُها عنه بِغَيْرِ عُذْرٍ؛ فَإنْ طَرَأَ مانِعٌ (كَحَيْضٍ) بَعْدَما مَضَى مِنْ [أَوَّلِ] وَقْتِها ما يَسَعُها [بِدُونِ طُهْرِها لِمَنْ هو سَلِيمٌ مِنْ نَحْوِ سَلَسٍ]، و[ما يَسَعُها مَعَ] طُهْرِها لِنَحْوِ [مَرِيضِ] سَلَسٍ، لَزِمَهُ قَضاؤُها؛ أو زالَ المانِعُ وقَدْ بَقِيَ مِنَ الوَقْتِ قَدْرُ تَكْبِيرَةٍ لَزِمَتْهُ، وكَذا [يَلْزَمُهُ] ما قَبْلَها إنْ جُمْعِتْ مَعَها، [إذا امْتَدَّتِ السَّلامَةُ مِنَ المانِعِ قَدْرًا يَسَعُ ذٰلك].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 111;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 112, 'فَصْلٌ : فِيما يَجِبُ على وُلاةِ الأُمُورِ', 'فَصْلٌ : فِيما يَجِبُ على وُلاةِ الأُمُورِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ [وُجُوبًا كِفائِيًّا] على وَلِيِّ الصَّبِيِّ والصَّبِيَّةِ المُمَيِّزَيْنِ أنْ يَأْمُرَهما بِالصَّلاةِ ويُعَلِّمَهُما أَحْكامَها بَعْدَ سَبْعِ سِنِينَ [قَمَرِيَّةٍ] ، ويَضْرِبَهُما على تَرْكِها بَعْدَ عَشْرِ سِنِينَ، كَصَوْمٍ أَطاقاهُ، ويَجِبُ عليه أَيْضًا تَعْلِيمُهُما [مِنَ العَقائِدِ والأَحْكامِ] ما [يُمْكِنُهُما فَهْمُهُ، وتَعْلِيمُهُما ما] يَجِبُ [بَعْدَ البُلُوغِ] عليهما وما يَحْرُمُ [كَذٰلكَ، وكَذا مَشْرُوعِيَّةُ نَحْوِ السِّواكِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 112;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'ويَجِبُ على وُلاةِ الأمْرِ [أيِ الخَلِيفَةِ ومَنْ يَنُوبُ عنه] قَتْلُ تارِكِ الصَّلاةِ [ولَوْ فَرْضًا واحِدًا] كَسَلًا [بَعْدَ إنْذارِهِ بِشُرُوطِهِ] إنْ لم يَتُبْ [أي إنْ لم يُصَلِّ] ، وحُكْمُهُ [أنَّهُ] مُسْلِمٌ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 112;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'ويَجِبُ على كُلِّ مُسْلِمٍ أَمْرُ أَهْلِهِ [أي زَوْجَتِهِ وأَهْلِ بَيْتِهِ ومَحارِمِهِ] بِها [أي الصَّلاةِ]، وقهرُهُمْ [على فِعْلِها إنْ قَصَّرُوا]، وتَعْلِيمُهُمْ أَرْكانَها وشُرُوطَها ومُبْطِلاتِها، و[كذٰلكَ] كُلُّ مَنْ قَدِرَ عليه مِنْ غَيْرِهِمْ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 112;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 113, 'فَصْلٌ : في فُرُوضِ الوُضُوءِ', 'فَصْلٌ : في فُرُوضِ الوُضُوءِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ شُرُوطِ الصَّلاةِ الوُضُوءُ، وفُرُوضُهُ سِتَّةٌ: الأوَّلُ: نِيَّةُ الطَّهارَةِ لِلصَّلاةِ بِالقَلْبِ، أو غَيْرُها مِنَ النِّيّاتِ المُجْزِئَةِ، عِنْدَ غَسْلِ الوَجْهِ؛ الثّاني: غَسْلُ الوَجْهِ جَمِيعِهِ، مِنْ مَنابِتِ شَعْرِ رَأْسِهِ إلى الذَّقَنِ، ومِنَ الأُذُنِ إلى الأُذُنِ، شَعَرًا وبَشَرًا، إلّا باطِنَ لِحْيَةِ الرَّجُلِ وعارِضَيْهِ إذا كَثُفْنَ؛ الثّالِثُ: غَسْلُ اليَدَيْنِ مَعَ المِرْفَقَيْنِ وما عليهما [كَشَعْرِ الذِّراعِ]؛ الرابِعُ: مَسْحُ الرّأْسِ أو بَعْضِهِ، ولَوْ شَعْرَةً في حَدِّهِ؛ الخامِسُ: غَسْلُ الرِّجْلَيْنِ مَعَ الكَعْبَيْنِ، أو مَسْحُ الخُفِّ إذا كَمَلَتْ شُرُوطُهُ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 113;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'السّادِسُ: التَّرْتِيبُ هٰكذا.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 113;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 114, 'فَصْلٌ : في نَواقِضِ الوُضُوءِ', 'فَصْلٌ : في نَواقِضِ الوُضُوءِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ويَنْقُضُ الوُضُوءَ: ما خَرَجَ مِنَ السَّبِيلَيْنِ إلّا المَنِيَّ؛ ومَسُّ قُبُلِ الآدَمِيِّ أو حَلْقَةِ دُبُرِهِ بِبَطْنِ الكَفِّ بِلا حائِلٍ؛ ولَمسُ [الذَّكَرِ] بَشَرَةَ [الأُنْثَى] الأجْنَبِيَّةِ [ولو زَوْجَةً] مَعَ كِبَرٍ [أو العَكْسُ، فَيَنْتَقِضُ وُضُوءُ اللّامِسِ والمَلْمُوسِ إذا اخْتَلَفَ جِنْسُهُما وكانَ كُلٌّ منهما يُشتَهَى ولم يَكُونا مَحْرَمَيْنِ]؛ وزَوالُ العَقْلِ إلّا نَوْمَ قاعِدٍ مُمَكِّنٍ مَقْعَدَتَهُ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 114;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 115, 'فَصْلٌ : فِيما يَجِبُ عَقِبَ ما يَخْرُجُ مِنَ السَّبِيلَيْنِ', 'فَصْلٌ : فِيما يَجِبُ عَقِبَ ما يَخْرُجُ مِنَ السَّبِيلَيْنِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ الاسْتِنْجاءُ مِنْ كُلِّ رَطْبٍ خارِجٍ مِنَ السَّبِيلَيْنِ غَيْرَ المَنِيِّ: [بِالغَسْلِ] بِالماءِ إلى أنْ يَطْهُرَ المَحَلُّ؛ أو [بأنْ] يَمْسَحَهُ ثَلاثَ مَسَحاتٍ أو أكْثَرَ، إلى أنْ يَنْقَى المَحَلُّ، وإنْ بَقِيَ الأثَرُ، بِقالِعٍ، طاهِرٍ، جامِدٍ [أي غَيْرِ مائعٍ ولا رَطْبٍ ولا مَطْحُونٍ]، غَيْرِ مُحْتَرَمٍ [كَالخُبْزِ] ، مِنْ غَيْرِ انْتِقالٍ، وقَبْلَ جَفافٍ [وإلّا وَجَبَ الماءُ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 115;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 116, 'فَصْلٌ : فِي ما يُوجِبُ الغُسلَ وفروضِهِ', 'فَصْلٌ : فِي ما يُوجِبُ الغُسلَ وفروضِهِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ شُرُوطِ الصَّلاةِ: الطَّهارَةُ عَنِ الحَدَثِ الأَكْبَرِ، وهو الغُسْلُ [ويَتَيَمَّمُ إنْ عَجَزَ عنه]، والَّذِي يُوجِبُهُ خَمْسَةُ أَشْياءَ: خُرُوجُ المَنِيِّ والجِماعُ والحَيْضُ والنِّفاسُ والوِلادَةُ', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 116;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وفُرُوضُ الغُسْلِ اثْنانِ: نِيَّةُ رَفْعِ الحَدَثِ الأَكْبَرِ أو نَحْوُها، وتَعْمِيمُ جَمِيعِ البَدَنِ بَشَرًا وشَعَرًا وإنْ كَثُفَ [بِالماءِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 116;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 117, 'فَصْلٌ : في شُرُوطِ الطَّهارَةِ وأَرْكانِ التَّيَمُّمِ', 'فَصْلٌ : في شُرُوطِ الطَّهارَةِ وأَرْكانِ التَّيَمُّمِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'شَرْطُ الطَّهارَةِ: الإسْلامُ، والتَّمْيِيزُ، وعَدَمُ المانِعِ مِنْ وُصُولِ الماءِ إلى المَغْسُولِ، والسَّيَلانُ، وأنْ يَكُونَ الماءُ مُطَهِّرًا، بأنْ: لا يُسْلَبَ اسْمَهُ بِمُخالَطَةِ طاهِرٍ يَسْتَغْنِي الماءُ عنه، وأنْ لا يَتَغَيَّرَ بِنَجِسٍ ولو تَغَيُّرًا يَسِيرًا،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 117;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وإنْ كانَ الماءُ دُونَ القُلَّتَيْنِ زِيدَ [شَرْطانِ آخَرانِ لِيَكُونَ مُطَهِّرًا]:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 117;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'بِأنْ لا يُلاقِيَهُ نَجِسٌ غَيْرُ مَعْفُوٍّ عنه، و[أنْ] لا [يَكُونَ] اسْتُعْمِلَ في رَفْعِ حَدَثٍ أو إزالَةِ نَجَسٍ. ومَنْ لم يَجِدِ الماءَ أو كانَ يَضرُّهُ الماءُ تَيَمَّمَ، بَعْدَ:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 117;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'دُخُولِ الوَقْتِ، وزَوالِ النَّجاسَةِ [الَّتي لا يُعفَى عنها]، ومَعْرِفَةِ القِبْلَةِ، [ويَكُونُ] بِتُرابٍ [أو رَمْلٍ] خالِصٍ طَهُورٍ له غُبارٌ، في الوَجْهِ واليَدَيْنِ، يُرَتِّبُهُما بِضَرْبَتَيْنِ [على الأَقَلِّ]، بِنِيَّةِ اسْتِباحَةِ فَرْضِ الصَّلاةِ، [وتَكُونُ النِّيَّةُ] مَعَ النَّقْلِ ومَسْحِ أَوَّلِ الوَجْهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 117;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 118, 'فَصْلٌ : فِيما يَحْرُمُ بِالحَدَثِ الأَصْغَرِ وغَيْرِهِ', 'فَصْلٌ : فِيما يَحْرُمُ بِالحَدَثِ الأَصْغَرِ وغَيْرِهِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومَنِ انْتَقَضَ وُضُوؤُهُ حَرُمَ عليه: الصَّلاةُ، والطَّوافُ، وحَمْلُ المُصْحَفِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 118;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'ومَسُّهُ [أي المُصْحَفِ، ولو بِحائِلٍ]، إلّا الصَّبِيَّ لِلدِّراسَةِ [فَيَجُوزُ تَمْكِينُهُ مِنَ الحَمْلِ والمَسِّ مَعَ حَدَثِهِ]، وعلى الجُنُبِ [تَحْرُمُ]: هٰذه [الأَرْبعُ السّابِقَةُ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 118;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'وقِراءَةُ القُرْآنِ [بِصَوتٍ]، ومُكْثُ المَسْجِدِ [لا عُبُورُهُ]، وعلى الحائِضِ والنُّفَساءِ [تَحْرُمُ]: هٰذه [السِّتُّ السّابِقَةُ]، والصَّوْمُ قَبْلَ الانْقِطاعِ، وتَمْكِينُ الزَّوْجِ مِنَ الاسْتِمْتاعِ بِما بَيْنَ سُرَّتِها ورُكْبَتِها [بِالجِماعِ ولو بِحائِلٍ، واللَّمْسِ بِلا حائِلٍ ولو بِلا شَهْوَةٍ] قَبْلَ الغُسْلِ [الشَّرْعِيِّ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 118;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 119, 'فَصْلٌ : في النَّجاسَةِ وإزالَتِها', 'فَصْلٌ : في النَّجاسَةِ وإزالَتِها');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ شُرُوطِ الصَّلاةِ الطَّهارَةُ عَنِ النَّجاسَةِ: في البَدَنِ، والثَّوْبِ، والمَكانِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 119;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والمَحْمُولِ له، [كَقِنِّينَةٍ أو مِنْدِيلٍ، في يَدِهِ أو جَيْبِهِ]، فَإنْ لاقاهُ نَجِسٌ أو لاقَى ثِيابَهُ أو مَحْمُولَهُ بَطَلَتْ صَلاتُهُ إلّا أنْ يُلْقِيَهُ حالًا، أو يَكُونَ مَعْفُوًّا عَنْهُ كَدَمِ جُرْحِهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 119;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'ويَجِبُ إزالَةُ نَجِسٍ لم يُعْفَ عَنْهُ، [وذٰلك]: [في النَّجاسَةِ العَيْنِيَّةِ]: بِإزالَةِ العَيْنِ، مِنْ طَعْمٍ ولَوْنٍ ورِيحٍ [وحَجْمٍ]، بِالماءِ المُطَهِّرِ، و[في النَّجاسَةِ] الحُكْمِيَّةِ [أي الَّتِي لا يُدْرَكُ لَها حَجْمٌ ولا لَوْنٌ ولا طَعْمٌ ولا رِيحٌ]: بِجَرْيِ الماءِ [المُطَهِّرِ مَرَّةً] عليها، و[في النَّجاسَةِ] الكَلْبِيَّةِ: بِغَسْلِها سَبْعًا [بِالماءِ المُطَهِّرِ]، إحْداهُنَّ مَمْزُوجَةٌ [أي مُكَدَّرَةٌ] بِالتُّرابِ؛ والمُزِيلَةُ لِلْعَيْنِ وإنْ تَعَدَّدَتْ واحِدَةٌ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 119;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'ويُشْتَرَطُ [في التَّطْهِيرِ مِنَ النَّجاسَةِ] وُرُودُ الماءِ [عليها] إنْ كانَ قَلِيلًا [أي دُونَ القُلَّتَيْنِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 119;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 120, 'فَصْلٌ : في شُرُوطٍ أُخْرَى لِلصَّلاةِ', 'فَصْلٌ : في شُرُوطٍ أُخْرَى لِلصَّلاةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ شُرُوطِ الصَّلاةِ: اسْتِقْبالُ القِبْلَةِ، ودُخُولُ الوَقْتِ، والإسْلامُ، والتَّمْيِيزُ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 120;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والعِلْمُ بِفَرْضِيَّتِها [إذا كانَتْ صَلاةً مَفْرُوضَةً]، وأنْ لا يَعْتَقِدَ فَرْضًا مِنْ فُرُوضِها سُنَّةً، والسَّتْرُ بِما يَسْتُرُ لَوْنَ البَشَرَةِ لِجَمِيعِ بَدَنِ الحُرَّةِ إلّا الوَجْهَ والكَفَّيْنِ، وسَتْرُ ما بَيْنَ السُّرَّةِ والرُّكْبَةِ لِلذَّكَرِ والأَمَةِ، مِنْ كُلِّ الجَوانِبِ لا الأَسْفَلِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 120;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 121, 'فَصْلٌ : في مُبْطِلاتِ الصَّلاةِ', 'فَصْلٌ : في مُبْطِلاتِ الصَّلاةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وتَبْطُلُ الصَّلاةُ: بِالكَلامِ ولو بِحَرْفَيْنِ [غَيْرِ مُفْهِمَيْنِ] أو بِحَرْفٍ مُفْهِمٍ، إلّا إنْ نَسِيَ وقَلَّ، وبِالأَفْعالِ الكَثِيرَةِ المُتَوالِيَةِ [أو مَعًا]، كَثَلاثِ حَرَكاتٍ، [ولو ناسِيًا]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 121;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وبِالحَرَكَةِ المُفْرِطَةِ [كَوَثْبَةٍ، ولو ناسِيًا]، وبِزِيادَةِ رُكْنٍ فِعْليٍّ [عَمْدًا]، وبِالحَرَكَةِ الواحِدَةِ لِلَّعِبِ [ولو خَفِيفَةً]، وبِالأَكْلِ والشُّرْبِ، إلّا إنْ نَسِيَ وقَلَّ، وبِنِيَّةِ قَطْعِ الصَّلاةِ، وبِتَعْلِيقِ قَطْعِها [على أَمْرٍ ما]، وبِالتَّرَدُّدِ فيه [أي في قَطْعِها] ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 121;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'وبأنْ يَمْضِيَ رُكْنٌ مَعَ الشَّكِّ في نِيَّةِ التَّحَرُّمِ، أو يَطُولَ زَمَنُ الشَّكِّ، [وبِتَغْيِيرِ النِّيَّةِ، كَأَنْ قَلَبَ فَرْضًا نَفْلًا وعَكْسُهُ، إلّا لِعُذْرٍ شَرْعِيٍّ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 121;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 122, 'فَصْلٌ : في شُرُوطِ قَبُولِ الصَّلاةِ', 'فَصْلٌ : في شُرُوطِ قَبُولِ الصَّلاةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وشُرِطَ، مَعَ ما مَرَّ [مِنْ شُرُوطِ صِحَّةِ الصَّلاةِ]، لِقَبُولِها عِنْدَ اللهِ سُبْحانَهُ وتَعالى [أي نَيْلِ ثَوابِها ودَرَجاتِها]: أنْ يَقْصِدَ بِها وَجْهَ اللهِ وَحْدَهُ [أي وِجْهَةَ طاعَةِ اللهِ] ، وأنْ يَكُونَ مَأْكَلُهُ ومَلْبُوسُهُ ومُصَلّاهُ حَلالًا، وأنْ يُحضِرَ قَلْبَهُ فيها [بِأَنْ يَخْشَعَ قَلْبُهُ للهِ ولَوْ لَحْظَةً]، فَلَيْسَ لَهُ مِنْ صَلاتِهِ إلّا ما عَقَلَ [أي وَعَى]، وأنْ لا يُعْجَبَ بِها. [ومَعْنَى صِحَّةِ الصَّلاةِ دُونَ قَبُولِها، أنْ تَسْقُطَ عنه المُطالَبَةُ بِها دُونَ أنْ يَنالَ ثَوابَها الخاصَّ.]', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 122;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 123, 'فَصْلٌ : في أَرْكانِ الصَّلاةِ', 'فَصْلٌ : في أَرْكانِ الصَّلاةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'أَرْكانُ الصَّلاةِ سَبْعَةَ عَشَرَ رُكْنًا: الأوَّلُ: نِيَّةٌ بِالقَلْبِ [لِفِعْلِ الصَّلاةِ]، ويُعَيِّنُ ذاتَ السَّبَبِ والوَقْتِ، ويَنْوِي الفَرْضِيَّةَ في الفَرْضِ، [ومِثالُ النِّيَّةِ الكافِيَةِ أنْ يَنْوِيَ قائِلًا في ذِهْنِهِ: "أُصَلِّي فَرْضَ الظُّهْرِ"] ، [الثّانِي]: ويَقُولُ [بِلِسانِهِ]، بِحَيْثُ يُسْمِعُ نَفْسَهُ كَكُلِّ رُكْنٍ قَوْليٍّ: "اللهُ أَكْبَر"، [مَعَ اسْتِحْضارِ النِّيَّةِ بِقَلْبِهِ]، وهو ثانِي أرْكانِها، الثّالِثُ: القِيامُ في الفَرْضِ لِلْقادِرِ، الرّابِعُ: قِراءَةُ الفاتِحَةِ، بِالبَسْمَلَةِ، والتَّشْدِيداتِ، ومُوالاتِها، وتَرْتِيبِها، وإخْراجِ الحُرُوفِ مِنْ مَخارِجِها، وعَدَمِ اللَّحْنِ [أيْ الخَطَأِ في الحَرَكاتِ] المُخِلِّ بِالمَعْنَى، ويَحْرُمُ اللَّحْنُ الَّذِي لا يُخِلُّ [إذا تَعَمَّدَهُ]، ولا يُبْطِلُ، الخامِسُ: الرُّكُوعُ بِأنْ يَنْحَنِيَ بِحَيْثُ تَنالُ راحَتاهُ رُكْبَتَيْهِ، السّادِسُ: الطُّمَأْنِينَةُ فيه بِقَدْرِ سُبْحانَ اللهِ، السّابِعُ: الاعْتِدالُ بِأنْ يَنْتَصِبَ قائِمًا، الثّامِنُ: الطُّمَأْنِينَةُ فيه، التّاسِعُ: السُّجُودُ مَرَّتَيْنِ بِأنْ يَضَعَ جَبْهَتَهُ [ولَوْ بَعْضَها] على مُصَلّاهُ مَكْشُوفَةً ومُتَثاقِلًا بِها ومُنَكِّسًا [أيْ جاعِلًا أَسْفَلَهُ أَعْلَى مِنْ أَعْلاهُ]، ويَضَعَ شَيْئًا مِنْ رُكْبَتَيْهِ، ومِنْ بُطُونِ كَفَّيْهِ، ومِنْ بُطُونِ أَصابِعِ رِجْلَيْهِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 123;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'العاشِرُ: الطُّمَأْنِينَةُ فيه، الحادِي عَشَرَ: الجُلُوسُ بين السَّجْدَتَيْنِ، الثانِي عَشَرَ: الطُّمَأْنِينَةُ فيه، الثّالِثَ عَشَرَ: الجُلُوسُ، لِلتَّشَهُّدِ الأَخِيرِ وما بَعْدَهُ، الرّابِعَ عَشَرَ: التَّشَهُّدُ الأَخِيرُ، فَـ[ـأَكْمَلُهُ أَنْ] يَقُولَ: "التَّحِيّاتُ المُبارَكاتُ الصَّلَواتُ الطَّيِّباتُ للهِ، السَّلامُ عَلَيْكَ أيُّها النَّبِيُّ ورَحْمَةُ اللهِ وبَرَكاتُهُ، السَّلامُ عَلَيْنا وعلى عِبادِ اللهِ الصّالِحينَ، أَشْهَدُ أَنْ لا إلٰهَ إلّا اللهُ وأَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللهِ"، الخامِسَ عَشَرَ: الصَّلاةُ على النَّبِيِّ صَلَّى اللهُ عليه وسَلَّمَ، [و]أَقَلُّها: "اللّٰهُمَّ صَلِّ على مُحَمَّدٍ"، السّادِسَ عَشَرَ: السَّلامُ، [و]أَقَلُّهُ: "السَّلامُ عَلَيْكُمْ"، السّابِعَ عَشَرَ: التَّرْتِيبُ، فَإِنْ تَعَمَّدَ تَرْكَهُ، كَأَنْ سَجَدَ قَبْلَ رُكُوعِهِ بَطَلَتْ، وإِنْ سَها [كأنْ تَرَكَ الرُّكُوعَ] فَلْيَعُدْ إليه إلّا أنْ يَكُونَ في مِثْلِهِ أو بَعْدَهُ، فَتَتِمُّ بِهِ رَكْعَتُهُ، ولَغا ما سَها بِهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 123;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 124, 'فَصْلٌ : في الجَماعَةِ والجُمُعَةِ', 'فَصْلٌ : في الجَماعَةِ والجُمُعَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الجَماعَةُ على الذُّكُورِ، الأَحْرارِ، المُقِيمِينَ، البالِغِينَ، [العُقَلاءِ]، غَيْرِ المَعْذُورِينَ، فَرْضُ كِفايَةٍ؛ و[الجَماعَةُ] في الجُمُعَةِ فَرْضُ عَيْنٍ عليهم [أي المَذْكُورِينَ]، إذا كانُوا أَرْبَعِينَ، مُكَلَّفِينَ، [مُسْتَوْطِنِينَ]، في أَبْنِيَةٍ [فَلا تَجِبُ على أَهْلِ الخِيامِ]، و[تَجِبُ] على مَنْ نَوَى الإقامَةَ عِنْدَهُمْ أَرْبَعَةَ أيّامٍ صِحاحٍ [أي غَيْرَ يَوْمَيِ الدُّخُولِ والخُرُوجِ]، وعلى مَنْ بَلَغَهُ [بِالقُوَّةِ لا بِالفِعْلِ] نِداءُ صَيِّتٍ مِنْ طَرَفٍ يَلِيهِ مِنْ بَلَدِها؛ وشَرْطُها [أي الجُمُعَةِ]: وَقْتُ الظُّهْرِ، وخُطْبَتانِ قَبْلَها فيه يَسْمَعُهُما الأَرْبَعُونَ [بِالفِعْلِ لو أَصْغَوْا ولم يَكُنْ ضَجَّةٌ ، وأنْ تُصَلَّى جَماعَةً بِهِمْ، وأنْ لا تُقارِنَها [في تَكْبِيرَةِ الإحْرامِ] ولا تَسْبِقَها جُمُعَةٌ بِبَلَدِها [إلّا إذا شَقَّ الاقْتِصارُ على واحِدَةٍ] ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 124;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وأَرْكانُ الخُطْبَتَيْنِ: حَمْدُ اللهِ، والصَّلاةُ على النَّبِيِّ صَلَّى اللهُ عليه وسَلَّمَ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 124;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'والوَصِيَّةُ بَالتَّقْوَى، فيهما [أي أنَّ هٰذه الثّلاثَةَ المُتَقَدِّمَةَ أَرْكانٌ في كُلٍّ مِنَ الخُطْبتَيْنِ]؛ وآيَةٌ مُفْهِمَةٌ، في إحْداهُما؛ والدُّعاءُ لِلْمُؤْمِنِينَ، في الثّانِيَةِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 124;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'وشُرُوطُهُما: الطَّهارَةُ عَنِ الحَدَثَيْنِ، وعَنِ النَّجاسَةِ في البَدَنِ والمَكانِ والمَحْمُولِ، وسَتْرُ العَوْرَةِ، والقِيامُ، والجُلُوسُ [قَدْرَ الطُّمَأْنِينَةِ] بَيْنَهُما،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 124;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'والوِلاءُ بَيْنَهُما، [والوِلاءُ بَيْنَ أَرْكانِهِما]، و[الوِلاءُ] بَيْنَهُما وبَيْنَ الصَّلاةِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 124;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 6, NULL, NULL, 'وأنْ يَكُونا [أرْكانُهما] بِالعَرَبِيَّةِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 124;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 125, 'فَصْلٌ : في شُرُوطِ الاقْتِداءِ', 'فَصْلٌ : في شُرُوطِ الاقْتِداءِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على مَنْ صَلَّى مُقْتَدِيًا في جُمُعَةٍ أو غَيْرِها: أنْ لا يَتَقَدَّمَ على إمامِهِ في المَوْقِفِ والإحْرامِ، بَلْ تُبْطِلُ المُقارَنَةُ في الإحْرامِ، وتُكْرَهُ في غَيْرِهِ إلّا التَّأْمِينَ، ويَحْرُمُ تَقَدُّمُهُ بِرُكْنٍ فِعْلِيٍّ، وتَبْطُلُ بِرُكْنَيْنِ، وكَذا التَّأَخُّرُ بِهما لِغَيْرِ عُذْرٍ، وبِأَكْثَرَ مِنْ ثَلاثَةِ أَرْكانٍ طَوِيلَةٍ له [أي لِعُذْرٍ]، وأنْ يَعْلَمَ بِانْتِقالاتِ إمامِهِ [بِرُؤْيَتِهِ أو سَماعِ صَوْتِهِ أو رُؤْيَةِ بَعْضِ صَفٍّ يَراهُ أو نَحْوِ ذٰلك]، وأنْ يَجْتَمِعا في مَسْجِدٍ أو ثَلاثِمِائَةِ ذِراعٍ، وأنْ لا يَحُولَ بينهما حائلٌ يَمْنَعُ الاسْتِطْراقَ [أي المُرُورَ العادِيَّ، المُباشِرَ في غَيْرِ مَسْجِدٍ، وغَيْرَ المُباشِرِ في مَسْجِدٍ] ، وأنْ يَتَوافَقَ نَظْمُ صَلاتَيْهِما [فَلا تَصِحُّ صُبْحٌ خَلْفَ جِنازَةٍ مَثَلًا] ، وأنْ لا يَتَخالَفا في سُنَّةٍ تَفْحُشُ المُخالَفَةُ فيها [كَفِعْلِ التَّشَهُّدِ الأَوَّلِ إذا تَرَكَهُ الإمامُ]، وأنْ يَنْوِيَ الاقْتِداءَ مَعَ التَّحَرُّمِ في الجُمُعَةِ [والمُعادَةِ]، و[أنْ يَنْوِيَ الاقْتِداءَ] قَبْلَ المُتابَعَةِ [في فِعْلٍ أو سَلامٍ] وطُولِ الانْتِظارِ [لِأَجْلِ هذه المُتابَعَةِ]، في غَيْرِها [أي الجُمُعَةِ والمُعادَةِ] ، ويَجِبُ على الإمامِ نِيَّةُ الإمامَةِ في الجُمُعَةِ والمُعادَةِ، وتُسَنُّ في غَيْرِهِما.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 125;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'غَسْلُ المَيِّتِ، وتَكْفِينُهُ، والصَّلاةُ عليه، ودَفْنُهُ، فَرْضُ كِفايَةٍ، إذا كانَ مُسْلِمًا وُلِدَ حَيًّا؛ ووَجَبَ لِذِمِّيٍّ تَكْفِينٌ، ودَفْنٌ؛ ولِسِقْطٍ مَيِّتٍ [ظَهَرَ خَلْقُهُ] غَسْلٌ، وكَفْنٌ، ودَفْنٌ؛ ولا يُصَلَّى عليهما [أي الذِّمِّيِّ والسِّقْطِ، فَصَلاةُ الجِنازَةِ على الكافِرِ كُفْرٌ، وعلى السِّقْطِ حَرامٌ]؛ ومَنْ ماتَ في قِتالِ الكُفّارِ بِسَبَبِهِ كُفِّنَ في ثِيابِهِ فَإنْ لم تَكْفِهِ زِيدَ عَلَيْها ودُفِنَ، ولا يُغَسَّلُ ولا يُصَلَّى عليه [أي غَسْلُهُ والصَّلاةُ عليه يَحْرُمانِ]. وأقَلُّ الغَسْلِ: إزالَةُ النَّجاسَةِ، وتَعْمِيمُ جَمِيعِ بَشَرِهِ وشَعَرِهِ وإنْ كَثُفَ مَرَّةً بِالماءِ المُطَهِّرِ. وأقَلُّ الكَفَنِ: ساتِرُ جَمِيعِ البَدَنِ، وثَلاثُ لَفائِفَ لِمَنْ تَرَكَ تَرِكَةً [أي مِيراثًا] زائِدَةً عَنْ دَيْنِهِ ولم يُوصِ بِتَرْكِها [أي بِتَرْكِ الزِّيادَةِ على الواحِدَةِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 125;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'وأقَلُّ الصَّلاةِ عليه: أنْ يَنْوِيَ [ذَكَرٌ ولو صَبِيًّا مُمَيِّزًا] فِعْلَ الصَّلاةِ عليه، والفَرْضَ، ويُعَيِّنَ [المَيِّتَ ولو بِالإشارَةِ القَلْبِيَّةِ]، ويَقُولَ: "اللهُ أَكْبَر"، وهو قائمٌ إنْ قَدِرَ، ثُمَّ يَقْرَأَ الفاتِحَةَ، ثُمَّ يَقُولَ: "اللهُ أَكْبَر، اللّٰهُمَّ صَلِّ على مُحَمَّد"، ثُمَّ يَقُولَ: "اللهُ أَكْبَر، اللّٰهُمَّ اغْفِرْ لَهُ وارْحَمْهُ"، ثُمَّ يَقُولَ: "اللهُ أَكْبَر، السَّلامُ عَلَيْكُمْ"، ولا بُدَّ فيها مِنْ شُرُوطِ الصَّلاةِ، وتَرْكِ المُبْطِلاتِ، [وتَقَدُّمِ غُسْلِ المَيِّتِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 125;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'وأقَلُّ الدَّفْنِ: حُفْرَةٌ تَكْتُمُ رائحَتَهُ وتَحْرُسُهُ مِنَ السِّباعِ، ويُسَنُّ أنْ يُعَمَّقَ [القَبْرُ] قَدْرَ قامَةٍ وبَسْطَةٍ، ويُوَسَّعَ، ويَجِبُ تَوْجِيهُهُ [أي المَيِّتِ] إلى القِبْلَةِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 125;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 126, 'فَصْلٌ : فِيما تَجِبُ فيه الزَّكاةُ', 'فَصْلٌ : فِيما تَجِبُ فيه الزَّكاةُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وتَجِبُ الزَّكاةُ في: الإبِلِ [ذُكُورًا وإناثًا]، والبَقَرِ [حَتَّى الجَوامِيسِ، ذُكُورًا وإناثًا]، والغَنَمِ [الضَّأْنِ والمَعْزِ، ذُكُورًا وإناثًا]، والتَّمْرِ، والزَّبِيبِ، والزُّرُوعِ [أي الحُبُوبِ] المُقْتاتَةِ حالَةَ الاخْتِيارِ [الَّتِي تُجَفَّفُ وتُدَّخَرُ] ، والذَّهَبِ، والفِضَّةِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 126;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والمَعدِنِ [أي الذَّهَبِ والفِضَّةِ عِنْدَ اسْتِخْراجِهِما مِنْ مَنْجَمِهِما]، والرِّكازِ منهما [أي ما وُجِدَ مِمّا دُفِنَ قَبْلَ البِعْثَةِ المُحَمَّدِيَّةِ مِنَ الذَّهَبِ والفِضَّةِ]، وأمْوالِ التِّجارَةِ، والفِطْرِ [بَعْدَ رَمَضانَ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 126;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 127, 'فَصْلٌ : في زَكاةِ المَواشِي', 'فَصْلٌ : في زَكاةِ المَواشِي');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وأوَّلُ نِصابِ الإبِلِ خَمْسٌ، والبَقَرِ ثَلاثُونَ، والغَنَمِ أَرْبَعُونَ، فَلا زَكاةَ قَبْلَ ذٰلك؛ ولا بُدَّ [لِوُجُوبِ الزَّكاةِ فيها]: مِنَ الحَوْلِ بَعْدَ ذٰلك [أي أنْ تُمْضِيَ سَنَةً قَمَرِيَّةً في مِلْكِهِ بَعْدَ بُلُوغِها نِصابًا]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 127;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'ومِنَ السَّوْمِ في كَلَأٍ مُباحٍ [أي أنْ يَرْعاها مالِكُها أو مَأْذُونُهُ في مَرْعًى غَيْرِ مَمْلُوكٍ]، وألّا تَكُونَ عامِلَةً [في الحِراثَةِ ونَحْوِها]. فَيَجِبُ في كُلِّ خَمْسٍ مِنَ الإبِلِ: شاةٌ [مِنَ الغَنَمِ] ؛ وفي أَرْبَعِينَ مِنَ الغَنَمِ: شاةٌ جَذَعَـ[ـةُ] ضَأْنٍ، أو ثَنِيَّـ[ـةُ] مَعْزٍ، وفي ثَلاثِينَ مِنَ البَقَرِ: تَبِيعٌ، ثُمَّ إنْ زادَتْ ماشِيَتُهُ على ذٰلك وَجَبَ عليه أنْ يَتَعَلَّمَ ما أَوْجَبَهُ اللهُ تَعالَى عليه فيها.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 127;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 128, 'فَصْلٌ : في زَكاةِ الزُّرُوعِ', 'فَصْلٌ : في زَكاةِ الزُّرُوعِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وأمّا التَّمْرُ والزَّبِيبُ والزُّرُوعُ فَأَوَّلُ نِصابِها خَمْسَةُ أَوْسُقٍ، وهي ثَلاثُمِائَةِ صاعٍ بِصاعِهِ عليه الصَّلاةُ والسَّلامُ، ويُضَمُّ زَرْعُ العامِ بَعْضُهُ إلى بَعْضٍ [في حِسابِ النِّصابِ]، ولا يُكَمَّلُ جِنْسٌ بِجِنْسٍ [فَلا يُكَمَّلُ قَمْحٌ بِشَعِيرٍ مَثَلًا]؛ وتَجِبُ الزَّكاةُ بِبُدُوِّ الصَّلاحِ [لِلْأَكْلِ في الرُّطَبِ والعِنَبِ ولَوْ في حَبَّةٍ]، واشْتِدادِ الحَبِّ [في الزُّرُوعِ المُقْتاتَةِ ولَوْ في سُنْبُلَةٍ] ، ويَجِبُ فيها العُشْرُ [أي عَشَرَةٌ في المِائَةِ] إنْ لم تُسْقَ بِمُؤْنَةٍ [أي كُلْفَةٍ]، ونِصْفُهُ [أي خَمسَةٌ في المِائَةِ] إنْ سُقِيتْ بِها، وما زادَ على النِّصابِ أَخْرَجَ منه بِقِسْطِهِ، ولا زَكاةَ فِيما دُونَ النِّصابِ إلّا أنْ يَتَطَوَّعَ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 128;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 129, 'فَصْلٌ : في زَكاةِ النَّقْدَيْنِ وزَكاةِ التِّجارَةِ', 'فَصْلٌ : في زَكاةِ النَّقْدَيْنِ وزَكاةِ التِّجارَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وأمَّا الذَّهَبُ فَنِصابُهُ عِشْرُونَ مِثْقالًا، والفِضَّةُ مِائَتا دِرْهَمٍ، ويَجِبُ فِيهما رُبْعُ العُشْرِ [أي اثْنانِ ونِصْفٌ في المِائَةِ]، وما زادَ فَبِحسابِهِ، ولا بُدَّ [لِوُجُوبِ الزَّكاةِ] فِيهما مِنَ الحَوْلِ، إلّا ما حَصَلَ مِنْ مَعدِنٍ ورِكازٍ [فَلا يُشْتَرَطُ فِيهما الحَوْلُ لِوُجُوبِ الزَّكاةِ] فيُخْرِجُها [عَمّا بَلَغ منهما نِصابًا] حالًا، [وفي المَعْدِنِ رُبْعُ العُشْرِ أي اثْنانِ ونِصْفٌ في المِائَةِ]، وفي الرِّكازِ الخُمُسُ [أي عِشْرُونَ في المِائَةِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 129;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وأمّا زَكاةُ التِّجارَةِ فَنِصابُها نِصابُ ما اشْتُرِيَتْ بِهِ مَنَ النَّقْدَيْنِ، ولا يُعْتَبَرُ [في الحِسابِ] إلّا [المَوْجُودُ مِنْ مالِ التِّجارَةِ] آخِرَ الحَوْلِ، ويَجِبُ فِيها رُبْعُ عُشْرِ القِيمَةِ [أي اثْنانِ ونِصْفٌ في المِائَةِ، ذَهَبًا أو فِضَّةً حَسَبَ ما قُوِّمَتْ بِهِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 129;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, '[فائدَةٌ]: ومالُ الخَلِيطَيْنِ والخُلَطاءِ كَمالِ المُنْفَرِدِ في النِّصابِ والمُخْرَجِ إذا كَمَلَتْ شُرُوطُ الخُلْطَةِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 129;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 130, 'فَصْلٌ : في زَكاةِ الفِطْرِ', 'فَصْلٌ : في زَكاةِ الفِطْرِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وزَكاةُ الفِطْرِ تَجِبُ بِإِدْراكِ جُزْءٍ مِنْ رَمَضانَ وجُزْءٍ مِنْ شَوّالٍ على كُلِّ مُسْلِمٍ، عليه وعلى [أي عَنْ] مَنْ عليه نَفَقَتُهُمْ إذا كانُوا مُسْلِمِينَ، على كُلِّ واحِدٍ صاعٌ مِنْ غالِبِ قُوتِ البَلَدِ، إذا فَضَلَتْ عَنْ دَيْنِهِ وكِسْوَتِهِ ومَسْكَنِهِ وقُوتِهِ وقُوتِ مَنْ عليه نَفَقَتُهُمْ يَوْمَ العِيدِ ولَيْلَتَهُ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 130;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 131, 'فَصْلٌ : في مُسْتَحِقِّي الزَّكاةِ', 'فَصْلٌ : في مُسْتَحِقِّي الزَّكاةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وتَجِبُ النِّيَّةُ في جَمِيعِ أَنْواعِ الزَّكاةِ، [وتَصِحُّ] بَعْدَ الإفْرازِ [ أو عِنْدَهُ، وقَبْلَ الدَّفْعِ أو عِنْدَهُ]. ويَجِبُ صَرْفُها إلى مَنْ وُجِدَ مِنَ الفُقَراءِ، والمَساكِينِ، والعامِلِينَ عليها، والمُؤَلَّفَةِ قُلُوبُهُمْ، وفي الرِّقابِ، والغارِمِينَ، وفي سَبِيلِ اللهِ، وابْنِ السَّبِيلِ، ولا يَجُوزُ ولا يُجزِئُ صَرْفُها إلى غَيْرِهِمْ؛ [ولا يَجُوزُ دَفْعُها إلى كافِرٍ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 131;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 132, 'فَصْلٌ : فِيمَنْ يَجِبُ عليه الصَّوْمُ ومَنْ يَجُوزُ له الفِطْرُ', 'فَصْلٌ : فِيمَنْ يَجِبُ عليه الصَّوْمُ ومَنْ يَجُوزُ له الفِطْرُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ صَوْمُ شَهْرِ رَمَضانَ على كُلِّ مُسْلِمٍ مُكَلَّفٍ؛ ولا يَصِحُّ [الصَّوْمُ ولا يَجُوزُ] مِنْ حائِضٍ ونُفَساءَ، ويَجِبُ عليهما القَضاءُ؛ ويَجُوزُ الفِطْرُ لِمُسافِرٍ سَفَرَ قَصْرٍ، وإنْ لم يَشُقَّ عليه الصَّوْمُ، [ويَجِبُ عليه القَضاءُ]؛ ولمرِيضٍ، وحامِلٍ، ومُرْضِعٍ، [لكِنَّ الثَّلاثَةَ الأُخَرَ إذا] شَقَّ [الصَّوْمُ] عليهم مَشَقَّةً لا تُحتَمَلُ، [أو خافَتِ الأَخِيرَتانِ على نَفْسَيْهِما أو وَلَدَيْهِما، يَجُوزُ لَهُمُ] الفِطْرُ، ويَجِبُ عليهم القَضاءُ، [ويَجِبُ على الأَخِيرَتَيْنِ فِدْيَةٌ إنْ أَفْطَرَتا خَوْفًا على وَلَدَيْهِما فَقَطْ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 132;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 133, 'فَصْلٌ : في فَرائِضِ الصَّوْمِ وشُرُوطِه', 'فَصْلٌ : في فَرائِضِ الصَّوْمِ وشُرُوطِه');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ويَجِبُ التَّبْيِيتُ [في صِيامِ الفَرْضِ، بِأنْ يَنْوِيَ بَيْنَ الغُرُوبِ والفَجْرِ صِيامَ غَدٍ]، والتَّعْيينُ [بِأنْ يَسْتَحْضِرَ في ذِهْنِهِ أنَّهُ يَصُومُ عَنْ رَمَضانَ أو نَذْرٍ أو كَفّارَةٍ أو غَيْرِها] في النِّيَّةِ لِكُلِّ يَوْمٍ، والإمْساكُ عن: الجِماعِ، والاسْتِمْناءِ [أي التَّسَبُّبِ عَمْدًا بِخُرُوجِ مَنِيِّهِ بِنَحْوِ لَمسٍ]، والاسْتِقاءَةِ [أي التَّسَبُّبِ عَمْدًا في خَرُوجِ شَيْءٍ مِنْ مَعِدَتِهِ إلى فَمِهِ بِنَحْوِ أُصْبُعِهِ]، وعن الرِّدَّةِ [أي الخُرُوجِ مِنَ الإسْلامِ، بِقَوْلِ كُفْرٍ أو فِعْلِ كُفْرٍ أو اعْتِقادِ كُفْرٍ]، وعَنْ دُخُولِ عَيْنٍ جَوْفًا، إلّا رِيقَهُ الخالِصَ الطّاهِرَ مِنْ مَعْدِنِهِ [أي مَكانِ وُجُودِهِ الأَصْلِيِّ وهو فَمُهُ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 133;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'و[يُشْتَرَطُ لِصِحَّةِ الصَّوْمِ]: أنْ لا يُجَنَّ ولو لَحْظَةً، وأنْ لا يُغْمَى عليه كُلَّ اليَوْمِ [مِنَ الفَجْرِ إلى الغُرُوبِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 133;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 134, 'فَصْلٌ : فِيما يَحْرُمُ صَوْمُهُ', 'فَصْلٌ : فِيما يَحْرُمُ صَوْمُهُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ولا يَصِحُّ [ولا يَجُوزُ] صَوْمُ العِيدَيْنِ، وأيّامِ التَّشْرِيقِ، وكَذا النِّصْفُ الأَخِيرُ مِنْ شَعْبانَ ويَومُ الشَّكِّ، إلّا أنْ يَصِلَهُ [أي النِّصْفَ الأخِيرَ مِنْ شَعبانَ، ويَوْمَ الشَّكِّ] بِما قَبْلَهُ، أو [يَصُومَهُ] لِقَضاءٍ أو نَذْرٍ أو وِرْدٍ [كاعْتِيادِ سُنَّةِ صَوْمِ الاثْنَيْنِ والخَمِيسِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 134;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 135, 'فَصْلٌ : فِيمَنْ أَفْسَدَ صَوْمَ يَوْمٍ مِنْ رَمَضانَ بِجِماعٍ', 'فَصْلٌ : فِيمَنْ أَفْسَدَ صَوْمَ يَوْمٍ مِنْ رَمَضانَ بِجِماعٍ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومَنْ أَفْسَدَ صَوْمَ يَوْمٍ مِنْ رَمَضانَ ولا رُخْصَةَ له في فِطْرِهِ بِجِماعٍ، فَعَلَيْهِ الإثْمُ، والقَضاءُ فَوْرًا [أي بَعْدَ يَوْمِ عِيدِ الفِطْرِ]، وكَفّارةُ ظِهارٍ [وهي عِتْقُ رَقَبَةٍ، فَإنْ لم يَسْتَطِعْ فَصِيامُ شَهْرَيْنِ مُتَتابِعَيْنِ، فَإنْ لم يَسْتَطِعْ فَتَمْلِيكُ سِتِّينَ مِسْكِينًا لِكُلِّ واحِدٍ مِلْءُ الكَفَّيْنِ مِنْ غالِبِ قُوتِ البَلَدِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 135;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 136, 'فَصْلٌ : فِيمَن يَجِبُ عليه الحَجُّ والعُمْرَةُ', 'فَصْلٌ : فِيمَن يَجِبُ عليه الحَجُّ والعُمْرَةُ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ الحَجُّ والعُمْرَةُ في العُمْرِ مَرَّةً على المُسْلِمِ، الحُرِّ، المُكَلَّفِ، المُسْتَطِيعِ بِما يُوصِلُهُ ويَرُدُّهُ إلى وَطَنِهِ، فاضِلًا عن دَيْنِهِ، ومَسْكَنِهِ وكِسْوَتِهِ اللّائِقَيْنِ بِهِ، ومُؤْنَةِ مَنْ عليه مُؤْنَتُهُ مُدَّةَ ذَهابِهِ وإيابِهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 136;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 137, 'فَصْلٌ : في أَرْكانِ الحَجِّ والعُمْرَةِ', 'فَصْلٌ : في أَرْكانِ الحَجِّ والعُمْرَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وأرْكانُ الحَجِّ: الإحْرامُ [بِأَنْ يَقُولَ بِقَلْبِهِ: "دَخَلْتُ في عَمَلِ الحَجِّ"]، والوُقُوفُ بِعَرَفَةَ، والطَّوافُ بِالبَيْتِ، والسَّعْيُ بَيْنَ الصَّفا والمَرْوَةِ، والحَلْقُ أو التَّقْصِيرُ [وأَقَلُّهُ لِثَلاثِ شَعَراتٍ مِنَ الرَّأْسِ]، وهي [أي الأَرْكانُ المَذْكُورَةُ] إلّا الوُقُوفَ أرْكانُ العُمْرَةِ. ولهٰذه الأرْكانِ فُرُوضٌ وشُرُوطٌ لا بُدَّ مِنْ مُراعاتِها.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 137;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 138, 'فَصْلٌ : فِيما يَحْرُمُ على المُحْرِمِ والمُحْرِمَةِ', 'فَصْلٌ : فِيما يَحْرُمُ على المُحْرِمِ والمُحْرِمَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وحَرُمَ على مَنْ أَحْرَمَ: طِيبٌ [كَعِطْرٍ]، ودَهْنُ رَأْسٍ ولِحْيَةٍ [بِزَيْتٍ ونَحْوِهِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 138;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وإزالَةُ ظُفْرٍ وشَعْرٍ، وجِماعٌ ومُقَدِّماتُهُ [كَتَقْبِيلٍ بِشَهْوَةٍ]، وعَقْدُ نِكاحٍ [لَهُ ولِغَيْرِهِ، ولا يَنْعَقِدُ]، واصْطِيادُ صَيْدٍ مَأْكُولٍ بَرِّيٍّ [وَحْشِيٍّ]، و[يَحْرُمَ] على [الـ]ـرَجُلِ سَتْرُ رَأْسِهِ، و[يَحْرُمُ على الرَجُلِ] لُبْسُ مُحِيطٍ بِهِ، و[يَحْرُمُ] عليها [أي المَرْأَةِ] سَتْرُ وَجْهِها، و[يَحْرُمُ على المَرْأَةِ لُبْسُ] قُفّازٍ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 138;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 139, 'فَصْلٌ : فِيما يَجِبُ بِفِعْلِ مُحَرَّماتِ الإحْرامِ', 'فَصْلٌ : فِيما يَجِبُ بِفِعْلِ مُحَرَّماتِ الإحْرامِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'فَمَنْ فَعَلَ شَيْئًا مِنْ هٰذه المُحَرَّماتِ فَعَلَيْهِ الإثْمُ، والكَفّارَةُ، [أي الفِدْيَةُ، في غَيْرِ عَقْدِ الزَّواجِ]؛ ويَزِيدُ الجِماعُ بِالإفْسادِ، ووُجُوبِ القَضاءِ فَوْرًا [أي بِلا تَأْخِيرٍ] ، وإتْمامِ الفاسِدِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 139;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 140, 'فَصْلٌ : في واجِباتِ الحَجِّ والعُمْرَةِ', 'فَصْلٌ : في واجِباتِ الحَجِّ والعُمْرَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ويَجِبُ [في الحَجِّ والعُمْرَةِ]: أنْ يُحرِمَ مِنَ المِيقاتِ؛ و[يَجِبُ] في الحَجِّ:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 140;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'مَبِيتُ مُزْدَلِفَةَ [لَحْظَةً في النِّصْفِ الثّاني مِنْ لَيْلَةِ العِيدِ]، و[مَبِيتُ] مِنًى [أكْثَرَ مِنْ نِصْفِ كُلٍّ مِنْ لَيالي التَّشْرِيقِ] ، ورَمْيُ جَمْرَةِ العَقَبَةِ يَوْمَ النَّحْرِ [أي العِيدِ] ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 140;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'ورَمْيُ الجِمارِ الثَّلاثِ أيّامَ التَّشْرِيقِ، وطَوافُ الوَداعِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 140;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 141, 'فَصْلٌ : في حُكْمِ صَيْدِ الحَرَمَيْنِ ونَباتِهِما', 'فَصْلٌ : في حُكْمِ صَيْدِ الحَرَمَيْنِ ونَباتِهِما');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ويَحْرُمُ صَيْدُ الحَرَمَيْنِ [المَكِّيِّ والمَدَنِيِّ]، و[قَطْعُ] نَباتِهِما، على مُحْرِمٍ وحَلالٍ [أي غيرِ مُحْرِمٍ]، وتَزِيدُ مَكَّةُ [المُكَرَّمَةُ] بِوُجُوبِ الفِدْيَةِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 141;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 142, 'فَصْلٌ : فِيما يَجِبُ في المُعامَلاتِ والأَنْكِحَةِ', 'فَصْلٌ : فِيما يَجِبُ في المُعامَلاتِ والأَنْكِحَةِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على كُلِّ مُسْلِمٍ مُكَلَّفٍ أنْ لا يَدْخُلَ في شَيْءٍ حَتَّى يَعْلَمَ ما أَحَلَّ اللهُ مِنْهُ وما حَرَّمَ؛ لِأَنَّ اللهَ سُبْحانَهُ تَعَبَّدَنا [أي كَلَّفَنا] بِأَشْياءَ فَلا بُدَّ مِنْ مُراعاةِ ما تَعَبَّدَنا بِهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 142;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وقَدْ أَحَلَّ اللهُ البَيْعَ وحَرَّمَ الرِّبا، وقَدْ قَيَّدَ الشَّرْعُ هذا البَيْعَ، المُعَرَّفَ بِآلَةِ التَّعْريفِ، بِقُيُودٍ وشُرُوطٍ وأرْكانٍ لا بُدَّ مِنْ مُراعاتِها، فَعَلَى مَنْ أَرادَ البَيْعَ والشِّراءَ أنْ يَتَعَلَّمَ ذٰلك، وإلّا أَكَلَ الرِّبا، شاءَ أمْ أَبَى، وقَدْ قالَ رَسُولُ اللهِ صَلَّى اللهُ عليه وسَلَّمَ: «التّاجِرُ الصَّدُوقُ يُحْشَرُ يَوْمَ القِيامَةِ مَعَ [النَّبِيِّينَ و]الصِّدِّيقِينَ والشُّهَداءِ» [رَواهُ التِّرْمِذِيُّ وصَحَّحَهُ]، وما ذاكَ إلّا لِأَجْلِ ما يَلْقاهُ مِنْ مُجاهَدَةِ نَفْسِهِ وهَواهُ وقَهْرِهِما على إجْراءِ العُقُودِ على ما أَمَرَ اللهُ [أي الطَّرِيقِ الشَّرْعِيِّ]، وإلّا فَلا يَخْفَى ما تَوَعَّدَ اللهُ [بِهِ] مَنْ تَعَدَّى الحُدُودَ؛ ثُمَّ إنَّ بَقِيَّةَ العُقُودِ، مِنَ الإجارَةِ والقِراضِ والرَّهْنِ والوَكالَةِ والوَدِيعَةِ والعارِيَّةِ والشَّرِكَةِ والمُساقاةِ وغَيْرِها، كَذٰلك لا بُدَّ مِنْ مُراعاةِ شُرُوطِها وأرْكانِها.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 142;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'وعَقْدُ النِّكاحِ يَحْتاجُ إلى مَزِيدِ احْتِياطٍ وتَثَبُّتٍ حَذَرًا مِمّا يَتَرَتَّبُ على فَقْدِ ذٰلك.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 142;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 143, 'فَصْلٌ : في مَنْهِيّاتٍ مِنَ البُيُوعِ', 'فَصْلٌ : في مَنْهِيّاتٍ مِنَ البُيُوعِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَحْرُمُ الرِّبا فِعْلُهُ وأَكْلُهُ وأَخْذُهُ وكِتابَتُهُ وشَهادَتُهُ وحِيْلَتُهُ، وهو [أَنْواعٌ مِنها]: بَيْعُ أَحَدِ النَّقْدَيْنِ بِالآخَرِ نَسِيئَةً [أي لِأَجَلٍ]، أو [بَيْعُ أحَدِ النَّقْدَيْنِ بِالآخَرِ] بِغَيْرِ تَقابُضٍ [في مَجْلِسِ العَقْدِ ولَوْ بِغَيْرِ اشْتِراطِ أَجَلٍ]، أو [بَيْعُ أحَدِ النَّقْدَيْنِ] بِجِنْسِهِ كَذٰلك [أي نَسِيئَةً أو بِغَيْرِ تَقابُضٍ] ، أو [بَيْعُ أحَدِ النَّقْدَيْنِ بِجِنْسِهِ] مُتَفاضِلًا [بِالوَزْنِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 143;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'و[بَيْعُ] المَطْعُوماتِ بَعْضِها بِبَعْضٍ كَذٰلك [أي نَسِيئَةً أو بِغَيْرِ تَقابُضٍ ولَوْ بِغَيْرِ جِنْسِهِ، ومُتَفاضِلًا إنْ كانَ بِجِنْسِهِ] ؛ ويَحْرُمُ بَيْعُ ما لم يَقْبِضْهُ؛ و[يَحْرُمُ بَيْعُ] اللَّحْمِ بِالحَيَوانِ؛ و[يَحْرُمُ بَيْعُ] الدَّيْنِ بِالدَّيْنِ؛ و[يَحْرُمُ] بَيْعِ الفُضُوليِّ [وهو مَنْ يَبِيعُ ما لَيْسَ لَهُ عليه مِلْكٌ ولا وِلايَةٌ]؛ و[يَحْرُمُ بَيْعُ] ما لم يَرَهُ [إلّا في بَيْعِ المَوْصُوفِ في الذِّمَّةِ وفي السَّلَمِ]؛ و[يَحْرُمُ] بَيْعُ غَيْرِ المُكَلَّفِ وعليه [أي الشِّراءُ منه والبَيْعُ له]؛ و[يَحْرُمُ بَيْعُ] ما لا مَنْفَعَةَ فيه؛ أو [ما] لا قُدْرَةَ على تَسْلِيمِهِ [أي يَحْرُمُ بَيْعُهُ]؛ أو [بَيْعٌ] بِلا صِيغَةٍ [فَيَحْرُمُ] ؛ و[يَحْرُمُ] بَيْعُ ما لا يَدْخُلُ تَحْتَ المِلْكِ كَالحُرِّ والأَرْضِ المَواتِ؛ و[يَحْرُمُ] بَيْعُ المَجْهُولِ؛ و[يَحْرُمُ بَيْعُ] النَّجِسِ، كَالكَلْبِ [والدَّمِ] وكُلِّ مُسْكِرٍ [مائِعٍ]؛ و[يَحْرُمُ بَيْعُ] مُحَرَّمٍ [أي ما يَحْرُمُ اسْتِعْمالُهُ مُطْلَقًا] كالطُّنْبُورِ [والتِّمْثالِ المُجَسَّمِ لِحَيَوانٍ، والصَّلِيبُ ولو مِنْ ذَهَبٍ ولو لِلزِّينَةِ (ويَكْفُرُ مَنْ يَبِيعُهُ لِمَنْ يَعْلَمُ أنَّهُ يُرِيدُهُ لِلْكُفْرِ)] ؛ ويَحْرُمُ بَيْعُ الشَّيْءِ الحَلالِ الطّاهِرِ على مَنْ تَعْلَمُ أنَّهُ يُرِيدُ أنْ يَعْصِيَ بِهِ [كَبَيْعِ العِنَبِ لِمَنْ تَعْلَمُ أنَّهُ يُرِيدُهُ لِيَصْنَعَ منه خَمْرًا لِلشُّرْبِ المُحَرَّمِ] ؛ و[يَحْرُمُ بَيْعُ] الأَشْياءِ المُسْكِرَةِ [ولَوْ طاهِرَةً كَالحَشِيشَةِ] ؛ ولا يَصِحُ بَيْعُ المُكْرَهِ؛ ويَحْرُمُ بَيْعُ المَعِيبِ بِلا إظْهارٍ لِعَيْبِهِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 143;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'ولا تَصِحُّ قِسْمَةُ تَرِكَةِ مَيِّتٍ، ولا بَيْعُ شَيْءٍ منها، ما لم تُوَفَّ دُيُونُهُ ووَصاياهُ، وتُخرَجْ أُجْرَةُ حَجَّةٍ وعُمْرَةٍ إنْ كانا عليه، إلّا أنْ يُباعَ شَيْءٌ [مِنَ التَّرِكَةِ] لِقَضاءِ هٰذه الأَشْياءِ، فَالتَّرِكَةُ كَمَرْهُونٍ بِذٰلك؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 143;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'كـ[ـذٰلك يَحْرُمُ بَيْعُ] رَقِيقٍ جَنَى، ولَوْ بِأَخْذِ دانِقٍ، [و]لا يَصِحُّ بَيْعُهُ، حَتَّى يُؤَدَّى ما بِرَقَبَتِهِ، أوْ يَأْذَنَ الغَرِيمُ في بَيْعِهِ؛ ويَحْرُمُ أنْ يُفَتِّرَ رَغْبَةَ المُشْتَرِي أو البائعِ بَعْدَ اسْتِقْرارِ الثَّمَنِ لِيَبِيعَ عليه أو لِيَشْتَرِيَ منه، وبَعْدَ العَقْدِ في مُدَّةِ الخِيارِ أَشَدُّ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 143;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'و[يَحْرُمُ] أنْ يَشْتَرِيَ الطَّعامَ [أي القُوتَ كالقَمْحِ] وَقْتَ الغَلاءِ والحاجَةِ لِيَحْبِسَهُ ويَبِيعَهُ بِأَغْلَى؛ و[يَحْرُمُ] أنْ يَزِيدَ في [ثَمَنِ] سِلْعَةٍ لِيَغُرَّ غَيْرَهُ؛ و[يَحْرُمُ] أنْ يُفَرِّقَ بَيْنَ الجارِيَةِ ووَلَدِها قَبْلَ التَّمْيِيزِ [بِنَحْوِ بَيْعِ أَحَدِهما دُونَ الآخَرِ]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 143;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 6, NULL, NULL, 'و[يَحْرُمُ] أنْ يَغُشَّ [في البَيْعِ]؛ أو يَخُونَ في الكَيْلِ والوَزْنِ والذَّرْعِ والعَدِّ؛ أو يَكْذِبَ [في البَيْعِ]؛ ويَحْرُمُ أنْ يَبِيعَ القُطْنَ أو غَيْرَهُ مِنَ البَضائِعِ ويُقْرِضَ المُشْتَرِيَ مَعَهُ دَراهِمَ و[يَشتَرِطَ عليه أنْ] يَزِيدَ في ثَمَنِ تِلْكَ البِضاعَةِ لِأجْلِ القَرْضِ؛ و[يَحْرُمُ] أنْ يُقْرِضَ الحائكَ أو غَيْرَهُ مِنَ الأُجَراءِ و[يَشْتَرِطَ عليه أنْ] يَسْتَخْدِمَهُ بِأَقَلَّ مِنْ أُجْرَةِ المِثْلِ لِأَجْلِ ذٰلك القَرْضِ، ويُسَمُّونَ ذٰلك [القَرْضَ في هٰذه المُعامَلَةِ والَّتِي قَبْلَها] الرَّبْطَةَ؛ و[يَحْرُمُ] أنْ يُقْرِضَ الحَرّاثِينَ إلى وَقْتِ الحَصادِ [ويَشْتَرِطَ أنَّهُمْ يَنْتَظِرُونَ الحَصادَ] ثُمَّ يَبِيعُونَ عليه طَعامَهُمْ بِأَوْضَعَ مِنَ السِّعْرِ قَلِيلًا، ويُسَمُّونَ ذٰلك المَقْضِيَّ. وكَذا جُمْلَةٌ مِنْ مُعامَلاتِ أَهْلِ هٰذا الزَّمانِ - أو أَكْثَرُها - خارِجَةٌ عَنْ قانُونِ الشَّرْعِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 143;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 7, NULL, NULL, 'فَعَلَى مُرِيدِ رِضا رَبِّهِ [أيْ نَيْلِ ثَوابِهِ والفَوْزِ بِإِكْرامِهِ]، وسَلامَةِ دِينِهِ ودُنْياهُ، أنْ يَتَعَلَّمَ ما يَحِلُّ وما يَحْرُمُ، مِنْ عالِمٍ ،وَرِعٍ، ناصِحٍ، شَفِيقٍ على دِينِهِ؛ فَإنَّ طَلَبَ الحَلالِ فَرِيضَةٌ على كُلِّ مُسْلِمٍ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 143;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 144, 'فَصْلٌ : في النَّفَقاتِ الواجِبَةِ وما يُذْكَرُ مَعَها', 'فَصْلٌ : في النَّفَقاتِ الواجِبَةِ وما يُذْكَرُ مَعَها');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'يَجِبُ على المُوسِرِ نَفَقَةُ أُصُولِهِ المُعْسِرِينَ [أي الآباءِ والأُمَّهاتِ الفُقَراءِ] وإنْ قَدِرُوا على الكَسْبِ، ونَفَقَةُ فُرُوعِهِ [أي أَوْلادِهِ وأَحْفادِهِ] إذا أَعْسَرُوا وعَجَزُوا عَنِ الكَسْبِ لِصِغَرٍ أو زَمانَةٍ، ويَجِبُ على الزَّوْجِ نَفَقَةُ الزَّوْجَةِ ومَهْرُها، وعليه لَها مُتْعَةٌ [وهي مالٌ يَتَراضَيانِ عليه أو يُقَدِّرُهُ القاضِي إنْ تَنازَعا] إنْ طَلَّقَها [بِلا سَبَبٍ منها]، وعلى مالِكِ العَبِيدِ والبَهائِمِ نَفَقَتُهُمْ، وأنْ لا يُكَلِّفَهُمْ مِنَ العَمَلِ ما لا يُطِيقُونَ، ولا يَضْرِبَهُمْ بِغَيْرِ حَقٍّ؛ ويَجِبُ على الزَّوْجَةِ طاعَةُ الزَّوْجِ في نَفْسِها إلّا ما لا يحِلُّ، وأنْ لا تَصُومَ [نَفْلًا] ولا تَخْرُجَ مِنْ بَيْتِهِ إلّا بِإذْنِهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 144;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 145, 'فَصْلٌ : في واجِباتِ القَلْبِ', 'فَصْلٌ : في واجِباتِ القَلْبِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'مِنَ الواجِباتِ القَلْبِيَّةِ: الإيمانُ بِاللهِ [كما تَقَدَّمَ بَيانُهُ في بابِ أُصُولِ الدِّينِ]، و[الإيمانُ] بِما جاءَ عَنِ اللهِ [كما تَقَدَّمَ بَيانُهُ في بابِ أُصُولِ الدِّينِ]، والإيمانُ بِرَسُولِ اللهِ [كما تَقَدَّمَ بَيانُهُ في بابِ أُصُولِ الدِّينِ]، و[الإيمانُ] بِما جاءَ عَنْ رَسُولِ اللهِ [كما تَقَدَّمَ بَيانُهُ في بابِ أُصُولِ الدِّينِ]، والتَّصْدِيقُ [وهو مَعْنَى الإيمانِ] ، واليَقِينُ [وهو عَدَمُ الشَّكِّ فِيما يَجِبُ الإيمانُ بِهِ] ، والإخْلاصُ وهو العَمَلُ [بِالطّاعَةِ] للهِ وَحْدَهُ، والنَّدَمُ على المَعاصِي [لَكُوْنِها مُخالَفَةً لِأَمْرِ الخالِقِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 145;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والتَّوَكُّلُ [وهو الاعْتِمادُ] على اللهِ [في أُمُورِ الرِّزْقِ والسَّلامَةِ مِنَ الضَّرَرِ وغيرِ ذٰلك، وعَدَمُ الرُّكُونِ إلى الأَسْبابِ مَعَ الأَخْذِ بِها]، والمُراقَبَةُ للهِ [وهي أنْ يُدِيمَ اسْتِحْضارَ أنَّ اللهَ مُطَّلِعٌ عليه يَعْلَمُ بِهِ ويَراهُ ويَسْمَعُهُ، لِيَدُومَ خَوْفُهُ مِنْ مُخالَفَةِ أَمْرِهِ] ، والرِّضا عَنِ اللهِ [وهو التَّسْلِيمُ له تَعالَى وتَرْكُ الاعْتِراضِ عليه سُبْحانَهُ]، وحُسْنُ الظَّنِّ بِاللهِ [بِأَنْ يَتَذَكَّرَ ما عَوَّدَهُ عليه مِنَ الإحْسانِ فَيَرْجُوَ مِثْلَهُ في المُسْتَقْبَلِ]، و[حُسْنُ الظَّنِّ] بِخَلْقِ اللهِ [بِألّا يَظُنَّ بِهِمْ سُوءًا بِغَيْرِ قَرِينَةٍ كافِيَةٍ شَرْعًا]، وتَعْظِيمُ شَعائرِ اللهِ [أي كُلِّ ما جُعِلَ عَلَمًا على طاعَةٍ كَالصَّلاةِ، والمُرادُ تَعْظِيمُ كُلِّ ما عَظَّمَهُ الشَّرْعُ]، والشُّكْرُ على نِعَمِ اللهِ [أي عَدَمُ اسْتِعْمالِها في مَعْصِيَةٍ]، والصَّبْرُ على أداءِ ما أَوْجَبَ اللهُ، والصَّبْرُ عَمّا حَرَّمَ اللهُ [أي على البُعْدِ عَنِ الحَرامِ]، و[الصَّبْرُ] على ما ابْتَلاكَ اللهُ به [بِألّا يَدْفَعَكَ بَلاءٌ إلى مَعْصِيَةٍ]، والثِّقَةُ بِالرِّزْقِ [أي بِأنَّ ما كُتِبَ لَكَ أنْ تَنْتَفِعَ بِهِ لَنْ يَفُوتَكَ]، واتِّهامُ النَّفْسِ [فِيما تَأمُرُهُ بِهِ خَشْيَةَ أنْ تَكُونَ تُخادِعُ لِلتَّوَصُّلِ إلى مُحَرَّمٍ]، وعَدَمُ الرِّضا عنها [أي عَنِ النَّفْسِ، بِتَذَكُّرِ تَقْصِيرِها]، وبُغْضُ الشَّيْطانِ [بِالمَيْلِ إلى مُخالَفَتِهِ]، وبُغْضُ الدُّنْيا [بِعَدَمِ الالْتِفاتِ إلى ما يُلهِي منها عَنْ طاعَةِ اللهِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 145;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'وبُغْضُ أَهْلِ المَعاصِي [بِالمَيْلِ عنهم، والنُّفُورِ مِنْ مَعاصِيهِمْ، ورَفْضِ الاقْتِداءِ بِهِمْ فيها]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 145;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'ومَحبَّةُ اللهِ [تَعالَى بِتَوْطِينِ القَلْبِ على عِبادَتِهِ وَحْدَهُ واتِّباعِ أَوامِرِهِ واجْتِنابِ نَواهِيهِ]، و[مَحَبَّةُ] كَلامِهِ [تَعالَى، بِمُراعاةِ تَعْظِيمِ آياتِهِ والتَّسْلِيمِ له والعَمَلِ بِهِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 145;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'و[مَحَبَّةُ] رَسُولِهِ [تَعالَى، صَلّى اللهُ عليه وسَلَّمَ، بِالإيمانِ به وتَوْقِيرِهِ والمَيْلِ إلى كَمالِ اتِّباعِهِ، [ومَحَبَّةُ سائِرِ أَنْبِيائِهِ تَعالَى، بالإيمانِ بِهِم وتَعْظِيمِهِمْ]، و[مَحَبَّةُ] الصَّحابَةِ [بِاسْتِحْضارِ فَضْلِهِمْ، بِما لَهُمْ مِنْ سابِقَةٍ في الإسْلامِ، وشَرَفٍ بصُحْبَتِهِمْ لِلنَّبِيِّ، ونُصْرَتِهِمْ لَهُ صلَّى اللهُ عليه وسلَّمَ، وتَبْلِيغِهِمْ لِلدِّينِ]، و[محبَّةُ] الآلِ [بِمُراعاتِهِمْ إكْرامًا لِلنَّبِيِّ صَلَّى اللهُ عليه وسَلَّمَ، فَهُمْ أَهْلُهُ وذَوُو قَرابَتِهِ]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 145;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 6, NULL, NULL, 'و[مَحَبَّةُ المُهاجِرِينَ و]الأَنْصارِ [الَّذِينَ نَصَرُوا الدِّينَ مِنْ أَهْلِ مَكَّةَ المُكَرَّمَةِ والمَدِينَةِ المَنَوَّرَةِ، ولا سِيَّما السّابِقينَ الأَوَّلِينَ منهم]، و[مَحَبَّةُ] الصّالِحِينَ [بِتَعْظِيمِهِمْ والمَيْلِ إلَيْهِمْ وسُلُوكِ طَرِيقِهِمْ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 145;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 146, 'فَصْلٌ : في نَصِيحَةٍ نَفِيسَةٍ مِنْ عالِمٍ جَلِيلٍ', 'فَصْلٌ : في نَصِيحَةٍ نَفِيسَةٍ مِنْ عالِمٍ جَلِيلٍ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وقالَ سَيِّدُنا عَبْدُ اللهِ بْنُ عَلَوِيٍّ الحَدّادُ، رَضِيَ اللهُ عنه ونَفَعَنا بِهِ، في كِتابِهِ النَّصائحِ الدِّينِيَّةِ ما مَعْناهُ: "وهٰذه أوْصافٌ يَجِبُ أنْ يَتَحَلَّى بِها ويَتَّصِفَ بِها كُلُّ مُؤْمِنٍ"اهـ، وهي قَوْلُهُ قَبْلَ هٰذا بَقَلِيلٍ: "أنْ يَكُونَ خاشِعًا، مُتَواضِعًا، خائفًا، وَجِلًا، مُشْفِقًا، مِنْ خَشْيَةِ اللهِ تَعالَى، زاهِدًا في الدُّنيا، قانِعًا بِاليَسِيرِ منها، مُنْفِقًا لِلْفاضِلِ عَنْ حاجَتِهِ مِمّا في يَدِهِ، ناصِحًا لِعِبادِ اللهِ تَعالَى، مُشْفِقًا عليهم، رَحِيمًا بِهِم، آمِرًا بِالمَعْرُوفِ، ناهِيًا عَنِ المُنْكَرِ، مُسارِعًا في الخَيْراتِ، مُلازِمًا لِلْعِباداتِ، دالًّا على الخَيْرِ، داعِيًا إلى الهُدَى، ذا سَمْتٍ وتُؤَدَةٍ، ووَقارٍ وسَكِينَةٍ، حَسَنَ الأَخْلاقِ، واسِعَ الصَّدْرِ، لَيِّنَ الجانِبِ، مَخْفُوضَ الجَناحِ لِلْمُؤْمِنِينَ، لا مُتَكَبِّرًا ولا مُتَجَبِّرًا، ولا طامِعًا في النّاسِ، ولا حَرِيصًا على الدُّنْيا، ولا مُؤْثِرًا لَها على الآخِرَةِ، ولا جامِعًا لِلْمالِ، ولا مانِعًا له عَنْ حَقِّهِ، ولا فَظًّا ولا غَلِيظًا، ولا مُمارِيًا ولا مُجادِلًا ولا مُخاصِمًا، ولا قاسِيًا، ولا سَيِّئَ الأَخْلاقِ، ولا ضَيِّقَ الصَّدْرِ، ولا مُداهِنًا، ولا مُخادِعًا، ولا غاشًّا، ولا مُقَدِّمًا لِلْأَغْنِياءِ على الفُقَراءِ، ولا مُتَرَدِّدًا على السَّلاطِينِ، ولا ساكِتًا عَنِ الإنْكارِ عليهم مَعَ القُدْرَةِ، ولا مُحِبًّا لِلْجاهِ والمالِ والوِلاياتِ، بَلْ يَكُونُ كارِهًا لِذٰلك كُلِّهِ، لا يَدْخُلُ في شَيْءٍ منه، ولا يُلابِسُهُ، إلَّا مِنْ حاجَةٍ أو ضَرُورَةٍ" انْتَهَى كَلامُهُ رَضِيَ اللهُ عنه ونَفَعَنا بِهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 146;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, '[(1) يُرادُ مِنْ إضافَةِ المَعاصِي إلى جَوارِحِ البَدَنِ وأَعْضائِهِ، كَاليَدِ والبَطْنِ، في هٰذا البابِ، مُجَرَّدُ التَّقْسِيمِ لِتَسْهِيلِ التَّعْلِيمِ، وإلّا فَيَكْفِي أنْ يَعْرِفَ المُسْلِمُ تَحْرِيمَ هٰذه الأُمُورِ لِيَجْتَنِبَها، ويَخافَ منها، ولو لم يَعْرِفْ ما تُضافُ إليه مِنَ الجَوارِحِ والأَعْضاءِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 146;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, '(2) تَكُونُ الإضافَةُ في اللُّغَةِ لِأَدْنَى مُلابَسَةٍ أو عَلاقَةٍ، ولِذٰلك فَما يَذْكُرُهُ هٰذا البابُ مِنْ إضافَةِ المَعاصِي إلى بَعْضِ الجَوارِحِ قَدْ يَكُونُ سَبَبُهُ حَقِيقِيًّا جَلِيًّا، كَإضافَةِ مَعْصِيَةِ نَظَرِ العَوْراتِ إلى العَيْنِ، وقَدْ يَكُونُ مَجازِيًّا خَفِيًّا، كَإضافَةِ مَعْصِيَةِ أَخْذِ الرِّبا والانْتِفاعِ بِهِ إلى البَطْنِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 146;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, '(3) المَعْصِيَةُ قَدْ تَكُونُ كُفْرًا مُخْرِجًا مِنَ الإسْلامِ، وقَدْ تَكُونُ دُونَ ذٰلك، والمُؤَلِّفُ رَحِمَهُ اللهُ تَعالَى بَيَّنَ المَعاصِي المُخْرِجَةَ مِنَ الإسْلامِ مِنْ أَقْوالٍ وأَفْعالٍ واعْتِقاداتٍ في أَوَّلِ هٰذا الكِتابِ، لٰكِنَّهُ يَذْكُرُ أَيْضًا هُنا في تَقْسِيمِهِ المَعاصِي على الجَوارِحِ ما هُوَ كُفْرٌ منها مَعَ ما هو دُونَهُ، دُونَ أنْ يَلْتَزِمَ فَرْزَ الكُفْرِ عَمّا دُونَهُ، ولِذٰلك نَبَّهْتُ بَيْنَ مَعْقُوفَيْنِ على ما كانَ كُفْرًا منها؛ ومِنَ المَعْلُومِ أنَّ أَكْبَرَ الكَبائرِ وأَعْظَمَ المَعاصِي وأَشْنَعَ الذُّنُوبِ وأفْظَعَ الجَرائِمِ، شَرْعًا على الحَقِيقَةِ والإطْلاقِ، كُلُّ ما كانَ كُفْرًا، لأنَّهُ يُخْرِجُ مِنْ دِينِ الإسْلامِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 146;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, '(4) المَعْصِيَةُ قَدْ تَكُونُ كَبِيرَةً، وقَدْ تَكُونُ صَغِيرَةً، والمُؤَلِّفُ رَحِمَهُ اللهُ تَعالَى لم يَلْتَزِمْ تَمْيِيزَ الكَبائرِ مِنَ الصَّغائِرِ، واكْتفَى بِسَرْدِها بِلا فَرْزٍ، لِأَنَّ كُلًّا منها يَجِبُ اجْتِنابُهُ دائمًا والابْتِعادُ عنه مُطْلَقًا، ولِأَنَّ العاقِلَ مَتَى اسْتَحْضَرَ أنَّ المَعْصِيَةَ هِيَ مُخالَفَةٌ لِنَهْيِ الخالِقِ العَظِيمِ رَآها كَبِيرَةً، وإنْ كانَتْ صَغِيرَةً بِاعْتِبارِ عَدَمِ فُسُوقِ مُرْتَكِبِها، وغَيْرِ ذلِكَ مِنَ الاعْتِباراتِ.]', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 146;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 147, 'فَصْلٌ : في مَعاصِي القَلْبِ', 'فَصْلٌ : في مَعاصِي القَلْبِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي القَلْبِ: الرِّياءُ بِأَعْمالِ البِرِّ، وهو العَمَلُ لِأَجْلِ [نَيْلِ المَنْزِلَةِ والتَّعْظِيمِ عِنْدَ] النّاسِ، ويُحْبِطُ ثَوابَها [إذا قارَنَ العَمَلَ]، كَالعُجْبِ بِطاعَةِ اللهِ تَعالَى [المَذْكُورِ في النُّقْطَةِ التّالِيَةِ] ؛ [والعُجْبُ بِالطاعَةِ]، وهو شُهُودُ العِبادَةِ صادِرَةً عَنِ النّفْسِ، [وتَعْظِيمُ نَفْسِهِ مِنْ أَجْلِها، لِكَوْنِهِ] غائِبًا عَنْ [تَذَكُّرِ] المِنَّةِ [أي أنَّها فَضْلٌ مِنَ اللهِ]؛ والشَّكُّ في اللهِ [وهو كُفْرٌ]؛ والأَمْنُ مِنْ مَكْرِ [أي عِقابِ] اللهِ، [ومَعْناهُ الاسْتِرْسالُ في المَعاصِي اتِّكالًا على الرَّحْمَةِ]؛ والقُنُوطُ مِنْ رَحْمَةِ اللهِ، [وهو الجَزْمُ بِأنَّهُ لا بُدَّ أنْ يُعَذِّبَهُ في الآخِرَةِ]؛ والتَّكَبُّرُ على عِبادِ اللهِ، وهو رَدُّ الحَقِّ، واسْتِحْقارُ النّاسِ، ورُؤْيَتُهُ أنَّهُ خَيْرٌ مِنْ كَثِيرٍ مِنْ خَلْقِ اللهِ تَعالَى [مَعَ أنَّهُ يَجْهَلُ الخاتِمَةَ]؛ والحِقْدُ، وهو إضْمارُ العَداوَةِ [بِالعَزْمِ على الإضْرارِ بِمُسْلِمٍ، وأمّا] إذا عَمِلَ بِمُقْتَضاهُ ولم يَكْرَهْهُ [فهو مَعْصِيَةٌ أُخْرَى]؛ والحَسَدُ، وهو كَراهِيَةُ النِّعْمَةِ على المُسْلِمِ واسْتِثْقالُها [عليه] إذا لم يَكْرَهْهُ أو عَمِلَ بِمُقْتَضاهُ؛ والمَنُّ بِالصَّدَقَةِ [أي أنْ يُعَدِّدَ على الشَّخْصِ إحْسانَهُ إلَيْهِ بِقَصْدِ الإيذاءِ]، ويُبطِلُ ثَوابَها؛ والإصْرارُ على الذَّنْبِ [وهو تَصْمِيمُ القَلْبِ على تَكْرارِهِ]؛ وسُوءُ الظَّنِّ بِاللهِ [وقَدْ يَصِلُ إلى الكُفْرِ] ؛ و[سُوءُ الظَّنِّ] بِعبادِ اللهِ [بِلا مُسَوِّغٍ شَرْعِيٍّ]؛ والتَّكْذِيبُ بِالقَدَرِ [وهو كُفْرٌ]؛ والفَرَحُ بِالمَعْصِيَةِ منه أو مِنْ غَيْرِهِ؛ والغَدْرُ [وهو نَقْضُ العَهْدِ وخِيانَةُ الأَمانَةِ]، ولو بِكافِرٍ؛ والمَكْرُ [أي الخَدِيعَةُ لِلإضْرارِ]؛ وبُغْضُ الصَّحابَةِ والآلِ والصّالِحِينَ [وبُغْضُ جَمِيعِهِمْ كُفْرٌ]، والبُخْلُ بِما أَوْجَبَ اللهُ، والشُّحُّ [أي الحِرْصُ على أَخْذِ ما في أَيْدِي النّاسِ ولو بِالحَرامِ]، والحِرْصُ [أي الطَّمَعَ في حَقِّ غَيْرِكَ]، والاسْتِهانَةُ بِما عَظَّمَ اللهُ [وهي كُفْرٌ إنْ كانَتْ بِمَعْنَى الاسْتِخْفافِ، ومَعْصِيَةٌ دُونَ الكُفْرِ إنْ كانَتْ بِمَعْنَى ما يُشْعِرُ بِمُجَرَّدِ الإخْلالِ بِواجِبِ التَّعْظِيمِ] ، والتَّصْغِيرُ لِما عَظَّمَ اللهُ مِنْ طاعَةٍ أو مَعْصِيَةٍ أو قُرْآنٍ أو عِلْمٍ [شَرْعِيٍّ] أو جَنَّةٍ أو نارٍ، [وهو كُفْرٌ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 147;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 148, 'فَصْلٌ : في مَعاصِي البَطْنِ', 'فَصْلٌ : في مَعاصِي البَطْنِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي البَطْنِ: أكْلُ الرِّبا؛ و[أكْلُ] المَكْسِ [أي الضَّرائِبِ] ؛ و[أكْلُ] الغَصْبِ؛ و[أكْلُ] السَّرِقَةِ؛ و[أكْلُ] كُلِّ مَأْخُوذٍ بِمُعامَلَةٍ حَرَّمَها الشَّرْعُ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 148;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'وشُرْبُ الخَمْرِ، وحَدُّ الشّارِبِ [أي عُقُوبَتُهُ المُحَدَّدَةُ في الشَّرْعِ] أَرْبَعُونَ جَلْدَةً لِلْحُرِّ، ونِصْفُها لِلرَّقِيقِ، ولِلإمامِ الزِّيادَةُ تَعْزِيرًا [أي تَأْدِيبًا] ؛ ومنها أكْلُ [وشُرْبُ] كُلِّ مُسْكِرٍ؛ و[أكْلُ وشُرْبُ] كُلِّ نَجِسٍ؛ و[أكْلُ وشُرْبُ كلِّ] مُسْتَقْذَرٍ؛ وأكْلُ مالِ اليَتِيمِ؛ أو [أكْلُ] الأَوْقافِ على خِلافِ شَرْطِ الواقِفِ؛ و[أكْلُ] المَأْخُوذِ بِوَجْهِ الحَياءِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 148;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 149, 'فَصْلٌ : في مَعاصِي العَيْنِ', 'فَصْلٌ : في مَعاصِي العَيْنِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي العَيْنِ: النَّظَرُ [مِنَ الرِّجالِ] إلى النِّساءِ الأَجْنَبِيّاتِ [بِشَهْوَةٍ مُطْلَقًا، وبِغَيْرِ شَهْوَةٍ إذا كانَ إلى غَيْرِ الوَجْهِ والكَفَّيْنِ، وقِيلَ وبِغَيْرِ شَهْوَةٍ إلَيْهِما إذا كانَ لِغَيْرِ حاجَةٍ كَمُعامَلَةٍ]، وكَذا [يَحْرُمُ] نَظَرُهُنَّ إلَيْهِمْ [ أي نَظَرُ النِّساءِ إلى الرِّجالِ الأجانِبِ مُطْلَقًا إذا كانَ بِشَهْوَةٍ، وإلى ما بَيْنَ السُّرَّةِ والرُّكْبَةِ إذا كانَ بِدُونِ شَهْوَةٍ]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 149;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'و[يَحْرُمُ] نَظَرُ العَوْراتِ [مِنَ الآخَرِينَ مُطْلَقًا لِغَيْرِ حاجَةٍ شَرْعِيَّةٍ]:', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 149;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'فَيَحْرُمُ نَظَرُ الرَّجُلِ إلى شَيْءٍ مِنْ بَدَنِ المَرْأَةِ الأَجْنَبِيَّةِ غَيْرِ الحَلِيلَةِ [سِوَى الوَجْهِ والكَفَّيْنِ، ويَحْرُمُ على غَيْرِ الحَلِيلَةِ نَظَرُ ما بَيْنَ سُرَّةِ الرَّجُلِ ورُكْبَتِهِ]؛ ويَحْرُمُ عليها كَشْفُ شَيْءٍ مِنْ بَدَنِها [سِوَى الوَجْهِ والكَفَّيْنِ] بِحَضْرَةِ مَنْ يَحْرُمُ نَظَرُهُ إلَيْها [أي إلى عَوْرَتِها، وهي ما سِواهُما]،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 149;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'ويَحْرُمُ عليها وعليه [أي على كُلٍّ مِنَ الرَّجُلِ والمَرْأَةِ] كَشْفُ شَيْءٍ مِمّا بَيْنَ السُّرَّةِ والرُّكْبَةِ بِحَضْرَةِ مُطَّلِعٍ على العَوْراتِ، ولَوْ مَعَ [كَوْنِهِ مِنْ] جِنْسِـ[ـهِ أو جِنْسِها]، غَيْرِ حَلِيلٍ، ويَحْرُمُ عليهما كَشْفُ السَّوْأَتَيْنِ [منه، وما بَيْنَ السُّرَّةِ والرُّكْبَةِ منها]، في الخَلْوَةِ لِغَيْرِ حاجَةٍ، إلّا لِحَلِيلٍ، وحَلَّ مَعَ مَحْرَمِيَّةٍ، أو مَعَ جِنْسِيَّةٍ، أو [إلى] الصَّغِيرِ الَّذِي لا يُشتَهَى [ولو بِلا مَحْرَمِيَّةٍ ولا جِنْسِيَّةٍ]، نَظَرُ ما عَدا ما بَيْنَ السُّرَّةِ والرُّكْبَةِ إذا كانَ بِغَيْرِ شَهْوَةٍ، إلّا [إلى] صَبِيٍّ وصَبِيَّةٍ دُونَ سِنِّ التَّمْيِيزِ فيَحِلُّ نَظَرُهُ [أي كُلِّ جِسْمِهِ]، ما عَدا فَرْجَ الأُنْثَى لِغَيْرِ أُمِّها، [وحَلَّ كلُّ ذٰلك بَيْنَ الرَّجُلِ وزَوْجَتِهِ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 149;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'ويَحْرُمُ النَّظَرُ بِاسْتِحْقارٍ إلى مُسْلِمٍ؛ والنَّظَرُ في بَيْتِ الغَيْرِ بِغَيْرِ إذْنِهِ؛ أو [النَّظَرُ] في شَيْءٍ أَخْفاهُ كَذٰلك؛ ومُشاهَدَةُ المُنْكَرِ [بِحُضُورِهِ] إذا لم يُنْكِرْ، أو يُعذَرْ، أو لم يُفارِقْ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 149;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 150, 'فَصْلٌ : في مَعاصِي اللِّسانِ', 'فَصْلٌ : في مَعاصِي اللِّسانِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي اللِّسانِ: الغِيبَةُ، وهي ذِكْرُكَ أَخاكَ المُسْلِمَ بِما يَكْرَهُ وإنْ كانَ فيه [في خَلْفِهِ]؛ والنَّمِيمَةُ، وهي نَقْلُ القَوْلِ لِلإفْسادِ؛ والتَّحْرِيشُ مِنْ غَيْرِ نَقْلِ قَوْلٍ ولو بَيْنَ البَهائمِ [وهو التَحْرِيضُ على الإيذاءِ بِغَيْرِ حَقٍّ]؛ والكَذِبُ [عَمْدًا]، وهو الكَلامُ بِخِلافِ الواقِعِ؛ واليَمِينُ الكاذِبَةُ [أي الحَلِفُ بِاسْمٍ للهِ أو صِفَةٍ مِنْ صِفاتِهِ على أَمْرٍ يَعْلَمُ الحالِفُ أنَّهُ كَذِبٌ] ؛ وأَلْفاظُ القَذْفِ، وهي كَثِيرَةٌ حاصِلُها كلُّ كَلِمَةٍ تَنْسُبُ إنْسانًا أو أَحَدًا مِنْ قَرابَتِهِ إلى الزِّنا، فَهِي قَذْفٌ لمَنْ نُسِبَ الزِّنا إلَيْهِ، إمّا صَرِيحًا مُطْلَقًا، وإمّا كِنايَةً بِنِيَّةٍ، ويُحَدُّ القاذِفُ الحُرُّ ثَمانِينَ جَلْدَةً، والرقيقُ نِصْفَها؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 150;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'ومنها سَبُّ [أحَدِ] الصَّحابَةِ [أمّا سَبُّ جَمِيعِهِمْ فَهُوَ كُفْرٌ]؛ وشَهادَةُ الزُّورِ؛ والخُلْفُ في الوَعْدِ إذا وَعَدَهُ وهو يُضمِرُ الخُلْفَ؛ ومَطْلُ الغَنِيِّ [أي تَسْوِيفُهُ وتَأْخِيرُهُ وَفاءَ الدَّيْنِ الَّذِي طَلَبَهُ منه الدائِنُ مَعَ القُدْرَةِ]؛ والشَّتْمُ والسَّبُّ واللَّعْنُ [بِغَيْرِ حَقٍّ]؛ والاسْتِهْزاءُ بِالمُسْلِمِ؛ وكُلُّ كَلامٍ مُؤْذٍ له [أي لِلْمُسْلِمِ]؛ والكَذِبُ على اللهِ وعلى رَسُولِهِ [صَلَّى اللهُ عليه وسَلَّمَ، وقَدْ يَصِلانِ إلى حَدِّ الكُفْرِ] ؛ والدَّعْوَى الباطِلَةُ [عِنْدَ قاضٍ أو غَيْرِهِ]؛ والطَّلاقُ البِدْعِيُّ [أي أثناءَ الحَيْضِ أو طُهْرٍ جامَعَها فيه]؛ والظِّهارُ [وهو تَشْبِيهُ زَوْجَتِهِ في الحُرْمَةِ عليه بِمَحْرَمِهِ أو عُضْوٍ منها، والمرادُ منه التَّصْرِيحُ بِالامْتِناعِ عَنْ مُجامَعَتِها أَبَدًا]، وفيه كَفّارَةٌ إنْ لم يُطَلِّقْ فَوْرًا، وهي عِتْقُ رَقَبَةٍ مُؤْمِنَةٍ سَلِيمَةٍ، فَإنْ عَجَزَ صامَ شَهْرَيْنِ مُتَتابِعَيْنِ، فإنْ عَجَزَ مَلَّكَ سِتِّينَ مِسْكِينًا سِتِّينَ مُدًّا [مِمّا يَصِحُ لِزَكاةِ الفِطْرِ]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 150;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'ومنها [تَعَمُّدُ] اللَّحْنِ في القُرْآنِ [أي تَغْيِيرِ حَرَكاتِهِ] وإنْ لم يُخِلَّ بِالمَعْنَى؛ والسُّؤالُ [أي الشِّحاذَةُ] لِغَنِيٍّ بِمالٍ أو حِرْفَةٍ؛ والنَّذْرُ بِقَصْدِ إحْرامِ الوارِثِ [أي حِرمانِهِ مِنَ الإرْثِ]؛ وتَرْكُ الوَصِيَّةِ بَدَيْنٍ [لا يَعْلَمُهُ غَيْرُهُ] أو عَيْنٍ لا يَعْلَمُها غَيْرُهُ؛ والانْتِماءُ إلى غَيْرِ أَبِيهِ أو غَيْرِ مَوالِيهِ؛ والخِطْبَةُ على خِطْبَةِ أَخِيهِ؛ والفَتْوَى بِغَيْرِ عِلْمٍ [ولو صادَفَ الصَّوابَ]؛ وتَعْلِيمُ وتَعلُّمُ عِلْمٍ مُضِرٍّ [لِغَيْرِ سَبَبٍ شَرْعِيٍّ]؛ والحُكْمُ بِغَيْرِ حُكْمِ اللهِ؛ والنَدْبُ والنِّياحَةُ؛ وكُلُّ قَوْلٍ يَحُثُّ على مُحَرَّمٍ أو يُفَتِّرُ عن واجِبٍ؛ وكُلُّ كَلامٍ يَقْدَحُ في الدِّينِ أو أَحَدٍ مِنَ الأَنْبِياءِ أو في العُلَماءِ أو العِلْمِ [الشَّرْعِيِّ] أو الشَّرْعِ أو القُرْآنِ أو في شَيْءٍ مِنْ شَعائرِ اللهِ [وهو كُفْرٌ]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 150;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'ومنها التَّزْمِيرُ [أي العَزْفُ المُطْرِبُ على نَحْوِ المِزمارِ]؛ والسُّكُوتُ عَنِ الأَمْرِ بِالمَعْرُوفِ والنَّهْيِ عَنِ المُنْكَرِ بِغَيْرِ عُذْرٍ؛ وكَتْمُ العِلْمِ الدِّينِيِّ الواجِبِ مَعَ وُجُودِ الطّالِبِ [إذا لم يُوجَدْ ذُو أَهْلِيَّةٍ لِلتَّعْلِيمِ غَيْرُهُ]؛ والضَّحِكُ لِخُرُوجِ الرِّيحِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 150;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'أو [الضَّحِكُ] على مُسْلِمٍ اسْتِحْقارًا له؛ وكَتْمُ الشَّهادَةِ [إذا دُعِيَ إلَيْها، أو وَجَبَتْ عليه مِنْ غَيْرِ دَعْوَةٍ]؛ ونِسيانُ القُرآنِ [وفُسِّرَ بِتَرْكِ العَمَلِ بِهِ] ؛ وتَرْكُ رَدِّ السَّلامِ الواجِبِ عَلَيْكَ؛ والقُبْلَةُ المُحْرِّكَةُ [أي التَّقْبِيلُ بَيْنَ الزَّوْجَيْنِ مَعَ شَهْوَةٍ] لِلمُحْرِمِ بِنُسُكٍ [أي حَجٍّ أو عُمْرَةٍ]، و[مَعَ خَشْيَةِ الإنْزالِ] لِصائمِ فَرْضٍ، أو [التَّقْبِيلُ مُطْلَقًا] لمَنْ لا يَحِلُّ له قُبْلَتُه.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 150;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 151, 'فَصْلٌ : في مَعاصِي الأُذُنِ', 'فَصْلٌ : في مَعاصِي الأُذُنِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي الأُذُنِ: الاسْتِماعُ إلى كَلامِ قَوْمٍ أَخْفَوْهُ عنه، و[الاسْتِماعُ] إلى المِزمارِ والطُّنْبورِ؛ وسائرِ الأصْواتِ المُحَرَّمَةِ [كَسائرِ آلاتِ الطَّرَبِ النَّفْخِيَّةِ والوَتَرِيَّةِ وغَيْرِها]؛ وكَالاسْتِماعِ إلى الغِيبَةِ والنَّمِيمَةِ، وسائرِ الأَقْوالِ المحَرَّمَةِ؛ بِخِلافِ ما إذا دَخَلَ عليه السّماعُ قَهْرًا وكَرِهَهُ، ولَزِمَهُ الإنكارُ إنْ قَدِرَ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 151;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 152, 'فَصْلٌ : في مَعاصِي اليَدِ', 'فَصْلٌ : في مَعاصِي اليَدِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي اليَدِ: التَّطْفِيفُ في الكَيْلِ والوَزْنِ والذَّرْعِ [أي الغِشُّ فِيها] ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 152;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والسَّرِقَةُ، ويُحَدُّ إنْ سَرَقَ ما يُساوِي رُبْعَ دِينارٍ مِنْ حِرْزِهِ بِقَطْعِ يَدِهِ اليُمْنَى، ثُمَّ إنْ عادَ فَرِجْلُهُ اليُسْرَى، ثُمَّ يَدُهُ اليُسْرَى، ثُمَّ رِجْلُهُ اليُمْنَى؛ ومنها النَّهْبُ؛ والغَصْبُ؛ والمَكْسُ؛ والغُلُولُ؛ والقَتْلُ [بِغَيْرِ حَقٍّ]، وفيه الكَفّارَةُ مُطْلَقًا [أي حَتّى في الخَطَأِ]، وهي عِتْقُ رَقَبَةٍ مُؤْمِنَةٍ سَلِيمَةٍ، فَإنْ عَجَزَ صامَ شَهْرَيْنِ مُتَتابِعَيْنِ؛ وفي عَمْدِهِ القِصاصُ إلّا إنْ عَفَى عنه [الوارِثُ] على الدِّيَةِ أو مجَّانًا، وفي الخَطَأِ وشِبْهِهِ الدِّيَةُ، وهي مِائَةٌ مِنَ الإبِلِ في الذَّكَرِ الحُرِّ المُسْلِمِ، ونِصْفُها في الأُنْثَى الحُرَّةِ المُسْلِمَةِ، وتَخْتَلِفُ صِفاتُ [إبِلِ] الدِّيَةِ بِحَسَبِ القَتْلِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 152;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'ومنها الضَّرْبُ بِغَيْرِ حَقٍّ؛ وأَخْذُ الرَّشْوَةِ؛ وإعْطاؤُها [أي الرَّشْوَةِ إلّا إذا اضْطُرَّ إليها لِتَحْصِيلِ حَقٍّ أو دَفْعِ ظُلْمٍ]؛ وإحْراقُ الحَيَوانِ إلّا إذا آذَى وتَعَيَّنَ طَرِيقًا في الدَّفْعِ؛ والمُثْلَةُ بِالحَيَوانِ [أي تَقْطِيعُهُ حَيًّا]؛ واللَّعِبُ بِالنَّرْدِ، والطابِ، وكُلِّ ما فيه قِمارٌ، حَتَّى لَعِبُ الصِّبْيانِ بالجَوْزِ والكِعابِ [لا يَجُوزُ أنْ يُؤْذَنَ لهم به إنْ كانَ على وَجْهٍ مُحَرَّمٍ]؛ واللّهْوُ [أي العَزْفُ المُطْرِبُ] بِآلاتِ اللَّهْوِ [أي المُوسِيقا] المُحَرَّمَةِ كَالطُّنْبُورِ والرَّبابِ والمِزمارِ والأوْتارِ؛ ولمَسُ الأَجْنَبِيَّةِ [أي غَيْرِ زَوْجَتِهِ وأَمَتِه ومَحرَمِهِ] عَمْدًا بِغَيْرِ حائِلٍ [مطلقًا]، أو به بِشَهْوَةٍ ولَوْ مَعَ جِنْسٍ أو مَحْرَمِيَّةٍ؛ وتَصْوِيرُ الحَيوانِ [أي مُحاكاةُ صُورَةِ ذِي رُوحٍ، سَواءٌ كانَ بِحَجْمٍ أم بِدُونِهِ، سِوَى دُمْيَةِ البِنْتِ الصَّغِيرَةِ]؛ ومَنْعُ الزَّكاةِ أو بَعْضِها، بَعْدَ الوُجُوبِ والتّمَكُّنِ، أو إخْراجُ ما لا يُجْزِئُ، أو إعْطاؤُها مَنْ لا يَسْتَحِقُّها [كَإنْفاقِها في بِناءِ المساجِدِ]؛ ومَنْعُ الأَجِيرِ أُجْرَتَهُ؛ ومَنْعُ المُضْطَرِّ [المَعْصُومِ الدَّمِ] ما يَسُدُّهُ [أي ما يُنْقِذُهُ مِنَ الهَلاكِ]؛ وعَدَمُ إنْقاذِ غَرِيقٍ [مَعْصُومِ الدَّمِ]، مِنْ غَيْرِ عُذْرٍ فيهما [أي هذِهِ والَّتِي قَبْلَها]؛ وكِتابَةُ ما يَحْرُمُ النُّطْقُ به؛ والخِيانَةُ، وهي ضِدُّ النَّصِيحَةِ، فَتَشْمَلُ الأفْعالَ والأَقْوالَ والأَحْوالَ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 152;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 153, 'فَصْلٌ : في مَعاصِي الفَرْجِ', 'فَصْلٌ : في مَعاصِي الفَرْجِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي الفَرْجِ: الزِّنا واللِّواطُ، ويُحَدُّ [بالزِّنا أو اللِّواطِ] الحُرُّ المُحْصَنُ، ذَكَرًا أو أُنْثَى، بِالرَّجْمِ بِالحِجارَةِ المُعْتَدِلَةِ حَتَّى يَمُوتَ، وغَيْرُهُ [أي غَيْرُ المُحْصَنِ] بِماِئَةِ جَلْدَةٍ وتَغْرِيبِ سَنَةٍ لِلحُرِّ، ونِصْفِ ذٰلك لِلرَّقِيقِ؛ ومنها [شُذُوذُ] إتْيانِ البَهائِمِ ولو مِلْكَهُ؛ والاسْتِمْناءُ [أي اسْتِدْعاءُ خُرُوجِ المَنِيِّ] بِيَدِ غَيْرِ الحَلِيلَةِ [أي الزَّوْجَةِ والأَمَةِ الَّتِي تَحِلُّ له]؛ والوَطْءُ في الحَيْضِ، أو النِّفاسِ، أو بَعْدَ انْقِطاعِهِما وقَبْلَ الغُسْلِ، أو بَعْدَ غُسْلٍ بِلا نِيَّةٍ [مِنَ المُغْتَسِلَةِ]، أوْ مَعَ فَقْدِ شَرْطٍ مِنْ شُرُوطِهِ؛ والتَّكَشُّفُ [لِلْعَوْرَةِ] عِنْدَ مَنْ يَحْرُمُ نَظَرُهُ إليه [أي إلى عَوْرَتِهِ]، أو في خَلْوَةٍ لِغَيْرِ غَرَضٍ [كَاغْتِسالٍ أو تَبَرُّدٍ أو تَمَتُّعِ زَوْجٍ]، واسْتِقْبالُ القِبْلَةِ أو اسْتِدْبارُها بِبَوْلٍ أو غائِطٍ مِنْ غَيْرِ حائِلٍ [كَنَحْوِ جِدارٍ ارْتِفاعُهُ على الأَقَلِّ ثُلُثا ذِراعٍ تَقْرِيبًا يَسْتُرُ العَوْرَةَ خَلْفَهُ]، أو كانَ وبَعُدَ عنه أَكْثَرَ مِنْ ثَلاثَةِ أَذْرُعٍ، أو كانَ أقَلَّ مِنْ ثُلُثَيْ ذِراعٍ، إلّا في المُعَدِّ لِذٰلك؛ والتَّغَوُّطُ [والتَبَوُّلُ] على القَبْرِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 153;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والبَوْلُ في المَسْجِدِ ولَوْ في إناءٍ، و[البَوْلُ] على المُعَظَّمِ [كَالمُصْحَفِ، وهُوَ كُفْرٌ مَهْما كانَ مُرادُهُ]، وتَرْكُ الخِتانِ بَعْدَ البُلُوغِ [ولا يَحْرُمُ على وَجْهٍ].', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 153;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 154, 'فَصْلٌ : في مَعاصِي الرِّجْلِ', 'فَصْلٌ : في مَعاصِي الرِّجْلِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي الرِّجْلِ: المَشْيُ في مَعْصِيَةٍ، كَالمَشْيِ في سِعايَةٍ بِمُسْلِمٍ أو قَتْلِهِ أو فِيما يَضُرُّهُ بِغَيْرِ حَقٍّ [ولو لم يَفْعَلْ ما مَشَى إلَيْهِ]؛ وإِباقُ [أيْ هَرَبُ] العَبْدِ [مِنْ سَيِّدِهِ] والزَّوْجَةِ [مِنْ زَوْجِها]، ومَنْ عليه حَقٌّ عَمّا يَلْزَمُه مِنْ قِصاصٍ أو دَيْنٍ أو نَفَقَةٍ أو بِرِّ والدٍ أو تَرْبِيةِ أَطْفالٍ؛ والتَّبَخْتُرُ في المَشْيِ [أيْ المَشْيُ بِكِبْرٍ وخُيَلاءَ وتَعاظُمٍ]؛ وتَخَطِّي الرِّقابِ إلّا لفُرْجَةٍ؛ والمُرُورُ بَيْنَ يَدَيِ المُصَلِّي إذا كَمَلَتْ شُرُوطُ سُتْرَتِهِ، ومَدُّ الرِّجْلِ إلى المُصْحَفِ إذا كانَ غَيْرَ مُرْتَفِعٍ [ولم يَكُنْ في خِزانَةٍ مَرْدُودَةِ البابِ أو خَلْفَ حائِلٍ]؛ وكُلُّ مَشْيٍ إلى مُحَرَّمٍ؛ أو [كُلُّ] تَخَلُّفٍ عن واجِبٍ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 154;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('sullamtaufiq', 155, 'فَصْلٌ : في مَعاصِي البَدَنِ', 'فَصْلٌ : في مَعاصِي البَدَنِ');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ومِنْ مَعاصِي البَدَنِ: عُقُوقُ الوالِدَيْنِ [وما دُونَهُ مِنْ إيذائِهِما]؛ والفِرارُ مِنَ الزَّحْفِ [أي الهَرَبُ مِنْ بَيْنِ المُقاتِلِينَ في سَبِيلِ اللهِ بَعْدَ الحُضُورِ معهم في مَوْضِعِ القِتالِ]؛ وقَطِيعَةُ الرَّحِمِ؛ وإيذاءُ الجارِ، ولو كافِرًا له أمانٌ، إيذاءً ظاهِرًا؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 2, NULL, NULL, 'والاخْتِضابُ [أي تَلْوِينُ الشَعْرِ] بِالسَّوادِ؛ وتَشَبُّهُ الرِّجالِ بِالنِّساءِ وعَكْسُهُ [في المَلْبَسِ وغَيْرِهِ]؛ وإسْبالُ الثَّوْبِ لِلْخُيَلاءِ [أيْ تَطْوِيلُ الثَّوْبِ إلى ما دُونَ رُسْغِ القَدَمِ تَكَبُّرًا وبَطَرًا]؛ والحِنّاءُ في اليَدَيْنِ والرِّجْلَيْنِ لِلرَّجُلِ بِلا حاجَةٍ؛ وقَطْعُ الفَرْضِ بِغَيْرِ عُذْرٍ؛ وقَطْعُ نَفْلِ الحَجِّ والعُمْرَةِ [بِغَيْرِ عُذْرٍ]؛ ومُحاكاةُ المُؤْمِنِ [وهو المُسْلِمُ] اسْتِهْزاءً بِهِ؛ والتَّجَسُّسُ [أي التَّتَبُّعُ والبَحْثُ] على عَوْراتِ النّاس [أي عُيُوبِهِمْ]؛ والوَشْمُ؛ وهَجْرُ المُسْلِمِ فَوْقَ ثَلاثٍ [أيْ ثَلاثَةِ أَيّامٍ] لِغَيْرِ عُذْرٍ شَرْعِيٍّ؛ ومُجالَسَةُ المُبْتَدِعِ والفاسِقِ لِلإيناسِ [له على ضَلالِهِ]؛ ولُبْسُ الذَّهَبِ، والفِضَّةِ، والحَرِيرِ أو ما أَكْثَرُهُ وَزْنًا منه، لِلرَّجُلِ البالِغِ، إلّا خاتَمَ الفِضَّةِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 3, NULL, NULL, 'والخَلْوَةُ بِالأَجْنَبِيَّةِ [أي غَيْرِ المَحْرَمِ والزَّوْجَةِ والأَمَة]؛ وسَفَرُ المَرْأَةِ [لِغَيْرِ فَرْضِ الحَجِّ] بِغَيْرِ نَحْوِ مَحْرَمٍ؛ واسْتِخْدامُ الحُرِّ كُرْهًا [أي سُخْرَةً]؛ والاسْتِخْفافُ بِالعُلَماءِ [الشَّرْعِيِّينَ]، و[الاسْتِخْفافُ] بِالإمامِ [أي الخَلِيفَةِ] العادِلِ،', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 4, NULL, NULL, 'و[الاسْتِخْفافُ] بِالشائبِ المُسْلِمِ؛ ومُعاداةُ الوِلِيِّ؛ والإعانَةُ على المَعْصِيَةِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 5, NULL, NULL, 'وتَرْوِيجُ الزّائِفِ؛ واسْتِعْمالُ أَوانِي الذَّهَبِ والفِضَّةِ واتِّخاذُها [أي اقْتِناؤُها لِغَيْرِ اسْتِعمالٍ]؛ وتَرْكُ الفَرْضِ، أو فِعْلُهُ مَعَ تَرْكِ رُكْنٍ له أو شَرْطٍ، أو مَعَ فِعْلِ مُبْطِلٍ له؛ وتَرْكُ الجُمُعَةِ مَعَ وُجُوبِها عليه وإنْ صَلَّى الظُّهْرَ؛ وتَرْكُ نَحْوِ أَهْلِ قَرْيَةٍ الجَماعَةَ في المَكْتُوباتِ [أي الصَّلَواتِ المَفْرُوضَةِ]؛ وتَأْخِيرُ الفَرْضِ عَنْ وَقْتِهِ بِغَيْرِ عُذْرٍ؛ ورَمْيُ الصَّيْدِ بِالمُثَقَّلِ المُذَفِّفِ [أي ما يَقْتُلُ بِثِقْلِهِ كَالحَجَرِ]؛ واتِّخاذُ الحَيوانِ غَرَضًا [أي هَدَفًا لِلرِّمايَةِ]؛ وعَدَمُ مُلازَمَةِ المُعْتَدَّةِ لِلْمَسْكَنِ بِغَيْرِ عُذْرٍ؛ وعَدَمُ الإحْدادِ على الزَّوْجِ [المُتوَفَّى]؛ وتَنْجِيسُ المَسْجِدِ، وتَقْذِيرُه ولو بِطاهِرٍ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 6, NULL, NULL, 'والتَّهاوُنُ بِالحَجِّ بَعْدَ الاسْتِطاعَةِ إلى أنْ يَمُوتَ؛ والاسْتِدانَةُ لمنْ لا يَرْجُو وَفاءً لِدَيْنِهِ مِنْ جِهَةٍ ظاهِرَةٍ ولم يَعْلَمْ دائنُهُ بِذٰلك؛ وعَدَمُ انْظارِ المُعْسِرِ؛ وبَذْلُ المالِ في مَعْصِيَةٍ؛ والاسْتِهانَةُ بِالمُصْحَفِ [وهي كُفْرٌ إنْ كانَتْ نَحْوَ رَمْيِهِ في القَذَرِ، ومَعْصَيَةٌ دُونَ الكُفْرِ إنْ كانَتْ نَحْوَ مَسِّهِ بِلا وُضُوءٍ] ، و[الاسْتِهانَةُ] بِكُلِّ عِلْمٍ شَرْعِيٍّ [وهي كُفْرٌ إنْ كانَتْ بِمَعْنَى الاسْتِخْفافِ، ومَعْصِيَةٌ لَيْسَتْ كُفْرًا إن كانَتْ بِمَعْنَى ما يُشْعِرُ بِمُجَرَّدِ الإخْلالِ بِواجِبِ التَّعْظِيمِ] ؛ وتَمْكِينُ الصَّبِيِّ غَيْرِ المُميِّزِ منه [أي المُصْحَفِ مُطْلَقًا، والمُمَيِّزِ لِغَيْرِ الدِّراسَةِ]؛ وتَغْيِيرُ مَنارِ الأَرْضِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 7, NULL, NULL, 'أو التّصَرُّفُ في الشّارِعِ بِما لا يَجُوزُ [كأنْ يَسُدَّهُ أو يَضَعَ فيه ما يَضُرُّ بِالمارَّةِ]؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 8, NULL, NULL, 'واسْتِعْمالُ المُعارِ في غَيْرِ المَأْذُونِ فيه؛ أو زادَ على المُدَّةِ المَأْذُونِ له فِيها؛ أو أَعارَهُ لِغَيْرِهِ [بِلا إذْنٍ]؛ وتَحْجِيرُ المُباحِ، كَالمَرْعَى والاحْتِطابِ مِنَ المَواتِ [أي الأرْضِ الَّتِي لا يَمْلِكُها إنْسانٌ]، والمِلْحِ مِنْ مَعْدِنِهِ [أي مَنْجَمِهِ]، والنَّقْدَيْنِ وغَيْرِهِما، والماءِ لِلشُّرْبِ مِنَ المُسْتَخْلَفِ؛ واسْتِعْمالُ اللُّقَطَةِ قَبْلَ التَّمَلُّكِ [الَّذِي يَلِي التَّعْرِيفَ] بِشُرُوطِهِ؛ والجُلُوسُ [في مَكانِ المَعْصِيَةِ] مَعَ مُشاهَدَةِ المُنْكَرِ [أي العِلْمِ بِهِ] إذا لم يُعْذَرْ؛ والتَّطَفُّلُ في الوَلائِمِ، وهو الدُّخُولُ بِغَيْرِ إذْنٍ أو [إذا] أَدْخَلُوهُ حَياءً؛ وأنْ [يَكُونَ المَرْءُ بِحَيْثُ] يُكْرِمُـ[ـه] المَرْءُ اتِّقاءً لِشَرِّهِ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 9, NULL, NULL, 'وعَدَمُ التَّسْوِيَةِ بَيْنَ الزَّوْجاتِ [في النَّفَقَةِ والمَبِيتِ] ؛', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 10, NULL, NULL, 'وخُرُوجُ المَرْأَةِ مُتَعَطِّرةً أو مُتَزَيِّنَةً، ولَوْ مَسْتُورَةً وبِإذْنِ زَوْجِها، إذا كانَتْ تَمُرُّ على رِجالٍ أَجانِبَ [بِقَصْدِ اسْتِمالَتِهِمْ إلَيْها، أو تَشبُّهًا -في زِينَتِهَا- بالفَاسِقَاتِ العَاهِراتِ أو الكَافِراتِ، وإلا كُرِه]؛ والسِّحْرُ [ولو لِفَكِّ سِحْرٍ أو لِتَحْبِيبٍ]؛ والخُرُوجُ عَنْ طاعَةِ الإمامِ [أي الخَلِيفَةِ]؛ والتَّوَلِّي على يَتِيمٍ أو مَسْجِدٍ أو لِقَضاءٍ ونَحْوِ ذٰلك مَعَ عِلْمِهِ بِالعَجْزِ عَنِ القِيامِ بِتِلْكَ الوَظِيفَةِ؛ وإيواءُ الظّالِمِ ومَنْعُهُ [أي حِمايَتُهُ] مِمَّنْ يُرِيدُ أَخْذَ الحَقِّ منه؛ وتَرْوِيعُ المُسْلِمِينَ [أي إخافَتُهُمْ]؛ وقَطْعُ الطَّرِيقِ، ويُحَدُّ [أي يُعاقَبُ] بِحَسَبِ جِنايَتِهِ، إمّا بِتَعْزِيرٍ [إنْ أَخافَ السَّبِيلَ فَقَطْ]، أو بِقَطْعِ يَدٍ ورِجْلٍ مِنْ خِلافٍ [إنْ أَخافَ وأَخَذَ المالَ ولم يَقْتُلْ]، أو بِقَتْلٍ وصَلْبٍ [إنْ أَخافَ وأَخَذَ المالَ وقَتَلَ]؛ ومنها عَدَمُ الوَفاءِ بِالنَّذْرِ؛ والوِصالُ في الصَّوْمِ [عَمْدًا بِغَيْرِ عُذْرٍ]؛ وأَخْذُ مَجْلِسِ غَيْرِهِ [في نَحْوِ مَسْجِدٍ]، أو زَحْمَتُهُ المُؤْذِيَةُ، أو أَخْذُ نَوْبَتِهِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 11, NULL, NULL, 'تَجِبُ التَّوْبَةُ مِنَ الذُّنُوبِ [صَغِيرِها وكَبِيرِها] فَوْرًا على كُلِّ مُكَلَّفٍ، وهي: [1] النَّدَمُ، [2] والإقْلاعُ، [3] والعَزْمُ على أنْ لا يَعُودَ إلَيْها، و[لا يُشْتَرَطُ] الاسْتِغْفارُ [بِاللِّسانِ] ، وإنْ كانَ الذَّنْبُ تَرْكَ فَرْضٍ قَضاهُ، أو تَبِعَةً لِآدَمِيٍّ قَضاهُ أو اسْتَرْضاهُ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 12, NULL, NULL, 'انْتَهَى ما قَدَّرَ اللهُ جَمْعَه، وأَرْجُو منه سُبْحانَهُ أنْ يُعِمَّ نَفْعَه، ويُكثِرَ في القُلُوبِ وَقْعَه، وأَطْلُبُ مِمَّنِ اطَّلعَ عليه مِنْ أُولِي المَعْرِفَةِ ورَأَى فيه خَطَأً أو زَلَلاً أنْ يُنَبِّهَ على ذٰلك، بِالرَّدِّ الصَّرِيحِ، لِيَحْذَرَ النّاسُ مِنَ اتِّباعِي على غَيْرِ الصَّوابِ، فَالحَقُّ أَحَقُّ أنْ يُتَّبَعَ، والإنْسانُ مَحَلُّ الخَطَأِ والنِّسْيانِ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 13, NULL, NULL, '﴿رَبَّنَا اغْفِرْ لَنَا وَلإِخْوَانِنَا الَّذِينَ سَبَقُونَا بِالإِيمَانِ وَلا تَجْعَلْ فِي قُلُوبِنَا غِلًّا لِلَّذِينَ ءامَنُوا رَبَّنَا إِنَّكَ رَءُوفٌ رَحِيمٌ﴾، اللّٰهُمَّ مَغْفِرَتُكَ أَوْسَعُ مِنْ ذُنُوبِنا، ورَحْمَتُكَ أَرْجَى عِنْدَنا مِنْ أَعْمالِنا، ﴿سُبْحَانَ رَبِّكَ رَبِّ الْعِزَّةِ عَمَّا يَصِفُونَ * وَسَلامٌ عَلَى المُرْسَلِينَ * وَالْحَمْدُ للهِ رَبِّ الْعَالَمِينَ﴾ - آمِينَ.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 14, NULL, NULL, '[ وفي آخِرِ النُّسْخَةِ المَطْبُوعَةِ بِدُونِ شَرْحٍ الَّتِي بِأَيْدِينا:[', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 15, NULL, NULL, 'قالَ مُؤَلِّفُهُ، سَيِّدُنا الحَبِيبُ عَبْدُ اللهِ بْنُ الحُسَيْنِ بْنِ طاهِرٍ عَلَوِيٌّ رَضِيَ اللهُ عنه: وكانَ الفَراغُ مِنْ إمْلائهِ فاتِحَةَ رَجَبٍ، سَنَةَ أَلْفٍ ومِائَتَيْنِ وإحْدَى وأَرْبَعِين، وصَلَّى اللهُ على سَيِّدِنا مُحَمَّدٍ وءالِهِ وصَحْبِهِ وسَلَّمَ', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'sullamtaufiq' AND bab_order = 155;
